function _doActivatePlan(planKey, opts = {}) {
  const { trial = (planKey !== 'free'), paid = false } = opts;
  S.subscription = {
    plan: planKey,
    activated: new Date().toISOString(),
    billing: S.subscription.billing || 'monthly',
    trialEnd: trial ? new Date(Date.now() + 14 * 86400000).toISOString() : null,
    paid: paid,
  };
  localStorage.setItem('baro_subscription', JSON.stringify(S.subscription));
  logActivity('plan', t('planActivated') + ' ' + planKey.toUpperCase() + (paid?' (payé)':trial?' (essai 14j)':''));
  showToast(paid ? `✅ ${planKey.toUpperCase()} activé — paiement reçu` : planKey === 'free' ? t('planActivated') : `🎁 Essai 14 jours activé — ${planKey.toUpperCase()}`, 'success');
  render();
}
function cancelPlan() {
  if (!confirm(t('confirmCancel') + ' ?')) return;
  S.subscription = { plan: 'free', activated: null, billing: 'monthly' };
  localStorage.setItem('baro_subscription', JSON.stringify(S.subscription));
  showToast(t('planFree'));
  render();
}
function setBilling(cycle) {
  S.subscription.billing = cycle;
  localStorage.setItem('baro_subscription', JSON.stringify(S.subscription));
  render();
}
function getPlanLimits(plan) {
  const limits = {
    free:       { articles: 50,  sales: 100,  locations: 1,  spectra: 5,  suppliers: 3,  orders: 10 },
    starter:    { articles: 500, sales: 2000, locations: 2,  spectra: 50, suppliers: 10, orders: 50 },
    pro:        { articles: -1,  sales: -1,   locations: 5,  spectra: -1, suppliers: -1, orders: -1 },
    enterprise: { articles: -1,  sales: -1,   locations: -1, spectra: -1, suppliers: -1, orders: -1 },
    // Legacy aliases (backward compatibility with older subscriptions)
    business:   { articles: -1,  sales: -1,   locations: -1, spectra: -1, suppliers: -1, orders: -1 },
  };
  return limits[plan] || limits.free;
}

// ── Expiry Date Helpers ───────────────────────
function getExpiryStatus(expiryDate) {
  if (!expiryDate) return null;
  const now = new Date(); now.setHours(0,0,0,0);
  const exp = new Date(expiryDate); exp.setHours(0,0,0,0);
  const diff = Math.ceil((exp - now) / 86400000);
  if (diff < 0) return { status: 'expired', days: Math.abs(diff), color: 'var(--danger)', label: t('expired') };
  if (diff === 0) return { status: 'today', days: 0, color: 'var(--danger)', label: t('expiryToday') };
  if (diff <= 7) return { status: 'soon', days: diff, color: 'var(--warning)', label: `${diff} ${t('daysLeft')}` };
  if (diff <= 30) return { status: 'ok', days: diff, color: 'var(--success)', label: `${diff} ${t('daysLeft')}` };
  return { status: 'ok', days: diff, color: 'var(--text-3)', label: `${diff} ${t('daysLeft')}` };
}
function getExpiringArticles() {
  return S.articles
    .filter(a => a.expiry)
    .map(a => ({ ...a, expiryInfo: getExpiryStatus(a.expiry) }))
    .filter(a => a.expiryInfo && a.expiryInfo.days <= 30)
    .sort((a, b) => a.expiryInfo.days - b.expiryInfo.days);
}

// ── Toast ──────────────────────────────────────
function showToast(msg, type='') {
  const el = document.createElement('div');
  el.className = `toast ${type}`;
  el.textContent = msg;
  $('toast-container').appendChild(el);
  setTimeout(() => {
    el.style.transition = 'opacity 0.25s';
    el.style.opacity = '0';
    setTimeout(() => el.remove(), 250);
  }, 2600);
}

// ── Auth Actions ───────────────────────────────
async function doLogin() {
  const email = S.authEmail.trim();
  const pwd   = S.authPwd;
  if (!email || !pwd) { showToast(t('fillAll'), 'error'); return; }
  try {
    const data = await api('POST', '/api/auth/login', { email, password: pwd });
    const u = data.user;
    S.token   = u.auth_token;
    const profile = u.profile || 'transformer';
    const bt = profile === 'reseller' ? 'reseller' : profile === 'transformer' ? 'maker' : (u.businessType || 'maker');
    S.session = {
      id: u.id, name: u.name, email: u.email, business: u.business_name,
      profile:         profile,
      businessType:    bt,
      currency:        u.currency        || 'XOF',
      currency_symbol: getCurrencySymbol(u.currency || 'XOF'),
      country:         u.country         || 'SN',
      language:        u.language        || 'fr',
      tax_rate:        u.tax_rate        || 0,
    };
    localStorage.setItem('stockr_business_type', bt);
    saveSession({ ...S.session, token: S.token });
    S.authEmail = S.authPwd = '';
    // Security tracking
    try {
      if (S.security) {
        S.security.lastLogin = new Date().toISOString();
        S.security.loginAttempts = [{ ts: new Date().toISOString(), success: true, ip: 'local' }, ...(S.security.loginAttempts || [])].slice(0, 20);
        localStorage.setItem('stockr_security', JSON.stringify(S.security));
      }
    } catch(_){}
    if (typeof logAudit === 'function') logAudit('auth', 'login', { email: u.email });
    // 2FA gate
    if (S.security?.twoFactorEnabled) {
      const code = String(Math.floor(100000 + Math.random() * 900000));
      S.twoFAPending = { email: u.email, code, expires: Date.now() + 5 * 60 * 1000, method: S.security.twoFactorMethod || 'email' };
      S.view = '2fa-verify';
      render();
      // Envoi réel (email/SMS) en arrière-plan
      (async () => {
        const method = S.security.twoFactorMethod || 'email';
        if (method === 'email') {
          const r = await _sendVerificationEmail(u.email, code, 'Connexion BARO');
          if (r.ok) showToast('📧 Code envoyé à ' + u.email, 'success');
          else {
            showToast('📧 Email non configuré — code : ' + code + ' (voir Paramètres > Sécurité)', 'info');
          }
        } else if (method === 'sms') {
          const phone = S.security.twoFactorPhone || u.phone || '';
          if (!phone) { showToast('Numéro SMS manquant — code : ' + code, 'info'); return; }
          const r = await _sendVerificationSMS(phone, code, 'Connexion BARO');
          if (r.ok) showToast('📱 SMS envoyé à ' + phone, 'success');
          else {
            showToast('📱 SMS non configuré — code : ' + code, 'info');
          }
        } else {
          // app-based TOTP / fallback
          showToast('🔐 Code : ' + code, 'info');
        }
      })();
      return;
    }
    S.view = 'home';
    render();
    await loadData();
  } catch(e) {
    try {
      if (S.security) {
        S.security.loginAttempts = [{ ts: new Date().toISOString(), success: false, ip: 'local' }, ...(S.security.loginAttempts || [])].slice(0, 20);
        localStorage.setItem('stockr_security', JSON.stringify(S.security));
      }
    } catch(_){}
    if (typeof logAudit === 'function') logAudit('auth', 'login_failed', { email });
    showToast(e.message || 'Email ou mot de passe incorrect', 'error');
  }
}

function v2FAVerify() {
  const p = S.twoFAPending;
  if (!p) { S.view = 'home'; render(); return ''; }
  const maskedEmail = p.email.replace(/(.{2}).*(@.*)/, '$1****$2');
  const method = p.method || 'email';
  const methodLbl = method === 'sms' ? '📱 SMS' : method === 'app' ? '🔐 App' : '📧 Email';
  // Affiche le code en clair si email/SMS non configuré (fallback dev/demo)
  const emailConfigured = !!localStorage.getItem('stockr_emailjs_public');
  const smsConfigured   = !!localStorage.getItem('stockr_sms_webhook');
  const showFallbackCode = (method === 'email' && !emailConfigured) || (method === 'sms' && !smsConfigured) || method === 'app';
  return `
  <div class="auth-wrap">
    <div class="auth-card">
      <div class="auth-logo">${IC.baro}<span>BARO</span></div>
      <div class="auth-title">🔐 Vérification</div>
      <div class="auth-sub">${methodLbl} · ${method==='sms'?('SMS envoyé à '+(S.security?.twoFactorPhone||'')):'Code envoyé à '+maskedEmail}</div>

      ${showFallbackCode ? `
      <div style="margin-top:16px;padding:14px;background:linear-gradient(135deg,#FEF3C7,#FDE68A);border-radius:12px;border:2px solid #F59E0B">
        <div style="font-size:11px;color:#92400E;font-weight:700;margin-bottom:6px;text-align:center">⚠️ ${emailConfigured||smsConfigured?'':'Envoi automatique non configuré'} — Votre code :</div>
        <div style="font-size:28px;font-weight:900;letter-spacing:6px;text-align:center;font-family:monospace;color:#78350F;user-select:all;cursor:copy" onclick="navigator.clipboard.writeText('${p.code}').then(()=>showToast('Code copié','success'))">${p.code}</div>
        <div style="display:flex;gap:6px;margin-top:8px">
          ${method==='email' ? `<button class="btn btn-ghost" style="flex:1;font-size:11px;padding:6px" onclick="_openMailtoVerification('${p.email}','${p.code}')">📧 Ouvrir email</button>` : ''}
          ${method==='sms' && S.security?.twoFactorPhone ? `<button class="btn btn-ghost" style="flex:1;font-size:11px;padding:6px" onclick="_openSmsVerification('${S.security.twoFactorPhone}','${p.code}')">📱 Ouvrir SMS</button>` : ''}
          <button class="btn btn-primary" style="flex:1;font-size:11px;padding:6px" onclick="S.twoFACodeInput='${p.code}';render()">⚡ Auto-remplir</button>
        </div>
      </div>` : ''}

      <div class="form-group" style="margin-top:20px">
        <label class="form-label">Code à 6 chiffres</label>
        <input class="input" id="tfa-code" type="text" inputmode="numeric" maxlength="6" placeholder="000000"
          style="letter-spacing:8px;text-align:center;font-size:24px;font-weight:700;font-family:monospace"
          value="${S.twoFACodeInput || ''}"
          oninput="S.twoFACodeInput=this.value.replace(/\\D/g,'').slice(0,6);if(this.value.length===6)verify2FA()">
      </div>

      <button class="btn btn-primary" style="width:100%;margin-top:10px" onclick="verify2FA()">Vérifier</button>

      <div style="text-align:center;margin-top:14px;display:flex;flex-direction:column;gap:8px">
        <button class="btn-link" onclick="resend2FA()" style="background:none;border:none;color:var(--accent);font-size:13px;cursor:pointer">🔄 Renvoyer le code</button>
        <button class="btn-link" onclick="cancel2FA()" style="background:none;border:none;color:var(--text-3);font-size:12px;cursor:pointer">← Retour</button>
      </div>

      <div style="margin-top:20px;padding:10px;background:var(--accent-light);border-radius:8px;font-size:11px;color:var(--text-2);text-align:center">
        💡 Le code expire dans 5 minutes
      </div>
    </div>
  </div>`;
}

// ── Envoi vérification EMAIL via EmailJS (gratuit, client-side, 200/mois) ──
async function _sendVerificationEmail(email, code, purpose) {
  const cfg = {
    serviceId:  localStorage.getItem('stockr_emailjs_service') || '',
    templateId: localStorage.getItem('stockr_emailjs_template') || '',
    publicKey:  localStorage.getItem('stockr_emailjs_public') || '',
  };
  if (!cfg.serviceId || !cfg.templateId || !cfg.publicKey) {
    // Fallback : mailto: deep link pour que l'utilisateur copie le code reçu dans l'app
    console.log('[2FA CODE]', code);
    return { ok: false, reason: 'emailjs_not_configured', code };
  }
  try {
    const body = {
      service_id: cfg.serviceId,
      template_id: cfg.templateId,
      user_id: cfg.publicKey,
      template_params: {
        to_email: email,
        to_name: email.split('@')[0],
        code: code,
        purpose: purpose || 'Vérification BARO',
        app_name: 'BARO',
        expires_min: '5'
      }
    };
    const res = await fetch('https://api.emailjs.com/api/v1.0/email/send', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });
    if (!res.ok) {
      const txt = await res.text();
      console.warn('EmailJS error', res.status, txt);
      return { ok: false, reason: 'http_' + res.status, detail: txt, code };
    }
    return { ok: true, code };
  } catch (e) {
    console.warn('EmailJS error', e);
    return { ok: false, reason: 'network', error: e, code };
  }
}

// ── Envoi vérification SMS via webhook configurable (Twilio Function, AT, etc.) ──
async function _sendVerificationSMS(phone, code, purpose) {
  const webhook = localStorage.getItem('stockr_sms_webhook') || '';
  const apiKey  = localStorage.getItem('stockr_sms_apikey') || '';
  if (!webhook) {
    // Pas de webhook → proposer sms: deep link pour envoyer manuellement
    console.log('[2FA SMS CODE]', code);
    return { ok: false, reason: 'sms_not_configured', code };
  }
  try {
    const body = {
      to: phone,
      message: `[BARO] Code de vérification : ${code} (valide 5 min). Ne le partagez pas.`,
      purpose: purpose || 'verification',
      code: code,
    };
    const res = await fetch(webhook, {
      method: 'POST',
      headers: Object.assign(
        { 'Content-Type': 'application/json' },
        apiKey ? { 'Authorization': 'Bearer ' + apiKey } : {}
      ),
      body: JSON.stringify(body),
    });
    if (!res.ok) {
      return { ok: false, reason: 'http_' + res.status, code };
    }
    return { ok: true, code };
  } catch(e) {
    console.warn('SMS webhook error', e);
    return { ok: false, reason: 'network', error: e, code };
  }
}

// Ouvre le vrai compose-email du navigateur/OS avec le code pré-rempli
function _openMailtoVerification(email, code) {
  const subj = encodeURIComponent('[BARO] Code de vérification');
  const body = encodeURIComponent(
    `Bonjour,\n\nVotre code de vérification BARO est : ${code}\n\nIl expire dans 5 minutes.\nNe le partagez avec personne.\n\n— L'équipe BARO`
  );
  window.open(`mailto:${encodeURIComponent(email)}?subject=${subj}&body=${body}`, '_blank');
}
function _openSmsVerification(phone, code) {
  const msg = encodeURIComponent(`[BARO] Code de vérification : ${code} (valide 5 min).`);
  window.location.href = `sms:${phone}?body=${msg}`;
}

async function verify2FA() {
  const p = S.twoFAPending;
  if (!p) return;
  if (Date.now() > p.expires) { showToast('Code expiré. Renvoyez-le.', 'error'); return; }
  const input = S.twoFACodeInput || '';
  if (input !== p.code) {
    if (typeof logAudit === 'function') logAudit('auth', '2fa_failed', { email: p.email });
    showToast('Code incorrect', 'error');
    return;
  }
  if (typeof logAudit === 'function') logAudit('auth', '2fa_success', { email: p.email });
  S.twoFAPending = null;
  S.twoFACodeInput = '';
  S.view = 'home';
  render();
  await loadData();
  showToast('🎉 Bienvenue !', 'success');
}

async function resend2FA() {
  const p = S.twoFAPending;
  if (!p) return;
  p.code = String(Math.floor(100000 + Math.random() * 900000));
  p.expires = Date.now() + 5 * 60 * 1000;
  const method = p.method || S.security?.twoFactorMethod || 'email';
  if (method === 'email') {
    const r = await _sendVerificationEmail(p.email, p.code, 'Connexion BARO');
    if (r.ok) showToast('📧 Code renvoyé à ' + p.email, 'success');
    else showToast('Code : ' + p.code + ' (email non configuré)', 'info');
  } else if (method === 'sms') {
    const phone = S.security?.twoFactorPhone || '';
    if (!phone) { showToast('Numéro manquant — code : ' + p.code, 'info'); return; }
    const r = await _sendVerificationSMS(phone, p.code, 'Connexion BARO');
    if (r.ok) showToast('📱 SMS renvoyé à ' + phone, 'success');
    else showToast('Code : ' + p.code + ' (SMS non configuré)', 'info');
  } else {
    showToast('Code : ' + p.code, 'info');
  }
}

function cancel2FA() {
  S.twoFAPending = null;
  S.twoFACodeInput = '';
  S.session = null;
  S.token = null;
  S.view = 'home';
  S.authView = 'login';
  render();
}

function authNextStep() {
  const name  = S.authName.trim();
  const email = S.authEmail.trim();
  const pwd   = S.authPwd;
  const pwd2  = S.authPwd2;
  if (!name || !email || !pwd) { showToast(t('fillAll'), 'error'); return; }
  if (pwd !== pwd2)            { showToast(t('pwdMismatch'), 'error'); return; }
  if (pwd.length < 6)          { showToast(t('pwdShort'), 'error'); return; }
  S.authStep = 2;
  render();
}

