// Appelé à l'inscription pour donner une base utilisable (articles, produits, clients, 1 semaine de ventes)
function seedDemoData(bt) {
  const now = Date.now();
  let seedArticles = [];
  let seedProducts = [];

  if (bt === 'reseller' || bt === 'mixed') {
    // Revendeur : articles = produits finis achetés/revendus avec marge
    seedArticles = [
      { id: now+1, name:'Sac à main cuir', stock:12, unit:'pcs', min:3, lead:14, ref:'SAC-001', price:25000, purchasePrice:12000, category:'Maroquinerie', perishable:false, expiry:'', image:'' },
      { id: now+2, name:'T-shirt coton',  stock:45, unit:'pcs', min:10,lead:7,  ref:'TSH-002', price:5000,  purchasePrice:1800, category:'Textile',      perishable:false, expiry:'', image:'' },
      { id: now+3, name:'Montre sport',   stock:8,  unit:'pcs', min:2, lead:10, ref:'MTR-003', price:35000, purchasePrice:18000,category:'Accessoires',  perishable:false, expiry:'', image:'' },
      { id: now+4, name:'Parfum 50ml',    stock:20, unit:'pcs', min:5, lead:14, ref:'PRF-004', price:15000, purchasePrice:6500, category:'Beauté',       perishable:false, expiry:'', image:'' },
      { id: now+5, name:'Lunettes soleil',stock:30, unit:'pcs', min:5, lead:7,  ref:'LUN-005', price:8000,  purchasePrice:2500, category:'Accessoires',  perishable:false, expiry:'', image:'' },
    ];
  }
  if (bt === 'maker' || bt === 'mixed') {
    // Transformateur : articles = matières premières
    seedArticles = seedArticles.concat([
      { id: now+10, name:'Farine blé',  stock:50, unit:'kg',  min:10, lead:5,  ref:'FAR-010', price:800, purchasePrice:500, category:'Matières', perishable:true,  expiry:'2026-08-15', image:'' },
      { id: now+11, name:'Sucre',       stock:30, unit:'kg',  min:5,  lead:5,  ref:'SUC-011', price:700, purchasePrice:450, category:'Matières', perishable:false, expiry:'', image:'' },
      { id: now+12, name:'Huile palme', stock:20, unit:'L',   min:5,  lead:7,  ref:'HUI-012', price:1500,purchasePrice:1000,category:'Matières', perishable:true,  expiry:'2026-10-30', image:'' },
      { id: now+13, name:'Levure',      stock:5,  unit:'kg',  min:2,  lead:10, ref:'LVR-013', price:4000,purchasePrice:2500,category:'Additifs', perishable:true,  expiry:'2026-06-01', image:'' },
      { id: now+14, name:'Emballage 1kg',stock:200,unit:'pcs',min:50, lead:7,  ref:'EMB-014', price:100, purchasePrice:50,  category:'Pack',     perishable:false, expiry:'', image:'' },
    ]);
    seedProducts = [
      { id: now+20, name:'Pain baguette', price:500,  purchasePrice:200,  composition:[ {id:now+10,name:'Farine blé',qty:0.3,unit:'kg'},{id:now+11,name:'Sucre',qty:0.02,unit:'kg'},{id:now+13,name:'Levure',qty:0.005,unit:'kg'}] },
      { id: now+21, name:'Pâtisserie',    price:1500, purchasePrice:600,  composition:[ {id:now+10,name:'Farine blé',qty:0.15,unit:'kg'},{id:now+11,name:'Sucre',qty:0.08,unit:'kg'},{id:now+12,name:'Huile palme',qty:0.05,unit:'L'}] },
      { id: now+22, name:'Beignet x10',   price:2000, purchasePrice:800,  composition:[ {id:now+10,name:'Farine blé',qty:0.4,unit:'kg'},{id:now+12,name:'Huile palme',qty:0.1,unit:'L'},{id:now+14,name:'Emballage 1kg',qty:1,unit:'pcs'}] },
    ];
  }

  // Clients démo
  const seedClients = [
    { id: now+50, name:'Aminata Traoré',  phone:'+225 07 12 34 56', email:'aminata@demo.ci', address:'Abidjan, Cocody', totalSpent:0, loyaltyPoints:0, createdAt: new Date(now - 30*86400000).toISOString() },
    { id: now+51, name:'Sekou Diaby',     phone:'+225 05 98 76 54', email:'sekou@demo.ci',   address:'Yamoussoukro',    totalSpent:0, loyaltyPoints:0, createdAt: new Date(now - 20*86400000).toISOString() },
    { id: now+52, name:'Mariam Kone',     phone:'+225 01 23 45 67', email:'mariam@demo.ci',  address:'Bouaké',          totalSpent:0, loyaltyPoints:0, createdAt: new Date(now - 10*86400000).toISOString() },
  ];

  // Ventes démo : 10 ventes réparties sur 7 jours
  const sellableItems = bt === 'reseller' ? seedArticles : seedProducts.length ? seedProducts : seedArticles;
  const seedSales = [];
  for (let i = 0; i < 10; i++) {
    const item = sellableItems[i % sellableItems.length];
    if (!item) continue;
    const qty = 1 + Math.floor(Math.random() * 3);
    const total = (item.price || 0) * qty;
    const cost  = (item.purchasePrice || 0) * qty;
    const daysAgo = Math.floor(Math.random() * 7);
    const saleDate = new Date(now - daysAgo * 86400000 - Math.random() * 86400000).toISOString();
    const client = seedClients[Math.floor(Math.random() * seedClients.length)];
    seedSales.push({
      id: now + 100 + i,
      productId: item.id,
      productName: item.name,
      qty,
      total,
      profit: total - cost,
      date: saleDate,
      paymentMethod: ['cash','wave','orange'][i%3],
      clientId: client.id,
      clientName: client.name,
      promoName: null,
      promoDiscount: 0,
    });
  }

  // Applique au state et persiste
  S.articles = seedArticles;
  S.products = seedProducts;
  S.clients  = seedClients;
  S.sales    = seedSales.sort((a,b) => new Date(b.date) - new Date(a.date));
  try {
    localStorage.setItem('stockr_articles', JSON.stringify(S.articles));
    localStorage.setItem('stockr_products', JSON.stringify(S.products));
    localStorage.setItem('stockr_clients',  JSON.stringify(S.clients));
    localStorage.setItem('stockr_sales',    JSON.stringify(S.sales));
  } catch(_){}
  if (typeof logAudit === 'function') logAudit('settings', 'demo_seeded', { bt, arts: seedArticles.length, prods: seedProducts.length, sales: seedSales.length });
}

async function doLogout() {
  if (!confirm('Êtes-vous sûr de vouloir vous déconnecter ?')) return;
  if (typeof logAudit === 'function') logAudit('auth', 'logout', { email: S.session?.email });
  try { await api('POST', '/api/auth/logout'); } catch(e) { /* ignore */ }
  clearSession();
  S.session = null; S.token = null;
  S.articles = []; S.products = []; S.sales = []; S.cart = [];
  S.currentMemberId = null;
  try { localStorage.removeItem('stockr_current_member'); } catch(_){}
  S.view = 'home'; S.authView = 'login';
  S.authEmail = S.authPwd = S.authPwd2 = S.authName = S.authBiz = '';
  render();
}

// ── App Actions ───────────────────────────────
async function applyStock() {
  if (typeof requirePermission === 'function' && !hasPermission('stock') && !hasPermission('all')) {
    requirePermission('stock');
    return;
  }
  const art = S.articles.find(a => a.id === S.selectedId);
  if (!art) return;
  if (S.action === 'remove' && art.stock < S.qty) { showToast(t('insufficientStock'), 'error'); return; }
  const newStock = S.action === 'add'
    ? Math.round((art.stock + S.qty) * 10) / 10
    : Math.round((art.stock - S.qty) * 10) / 10;
  try {
    await api('PUT', `/api/articles/${art.id}`, { quantity: newStock });
    art.stock = newStock;
    logMovement(art.name, S.action === 'add' ? 'entry' : 'exit', S.qty, S.action === 'add' ? t('reception') : t('withdrawal'));
    logActivity('stock', `${art.name}: ${S.action === 'add' ? '+' : '-'}${S.qty} ${art.unit}`);
    if (typeof logAudit === 'function') logAudit('stock', S.action === 'add' ? 'receive' : 'withdraw', { article: art.name, qty: S.qty, unit: art.unit, newStock });
    showToast(S.action === 'add' ? `+${S.qty} ${art.unit}` : `-${S.qty} ${art.unit}`);
    S.qty = 1;
    render();
  } catch(e) {
    showToast(e.message, 'error');
  }
}

async function deleteArticle(id) {
  if (typeof requirePermission === 'function' && !requirePermission('stock') && !requirePermission('all', true)) return;
  const art = S.articles.find(a => a.id === id);
  if (!art) return;
  try {
    await api('DELETE', `/api/articles/${id}`);
    S.products.forEach(p => { p.composition = p.composition.filter(c => c.id !== id); });
    S.articles = S.articles.filter(a => a.id !== id);
    if (typeof logAudit === 'function') logAudit('stock', 'delete_article', { name: art.name, id });
    showToast(`"${art.name}" supprimé`);
    nav('pantry');
  } catch(e) {
    showToast(e.message, 'error');
  }
}

function _resolveClientForSale() {
  if (S.saleNewClient) {
    const nameEl  = $('sale-new-client-name');
    const phoneEl = $('sale-new-client-phone');
    const name  = nameEl?.value?.trim();
    const phone = phoneEl?.value?.trim() || '';
    if (!name) return { clientId: null, clientName: null };
    const existing = S.clients.find(c => c.name.toLowerCase() === name.toLowerCase());
    if (existing) return { clientId: existing.id, clientName: existing.name };
    const newClient = { id: Date.now(), name, phone, email: '', address: '', loyaltyPoints: 0, createdAt: new Date().toISOString() };
    S.clients.push(newClient);
    localStorage.setItem('baro_clients', JSON.stringify(S.clients));
    S.saleNewClient = false;
    return { clientId: newClient.id, clientName: newClient.name };
  }
  const sel = $('sale-client');
  const clientId = sel ? parseInt(sel.value) || null : null;
  const client   = clientId ? S.clients.find(c => c.id === clientId) : null;
  return { clientId, clientName: client?.name || null };
}

function recordSale() {
  const sel   = $('sale-product');
  const qtyEl = $('sale-qty');
  if (!sel || !sel.value) { showToast(t('chooseProduct'), 'error'); return; }

  // ── Mode revendeur : vente directe depuis le stock ──
  if (S.authProfile === 'reseller' && sel.value.startsWith('art_')) {
    const artId = parseInt(sel.value.replace('art_', ''));
    const art = S.articles.find(a => a.id === artId);
    if (!art) return;
    const qty = Math.max(1, parseFloat(qtyEl.value) || 1);
    if (art.stock < qty) { showToast(`Stock insuffisant : ${art.name}`, 'error'); return; }
    art.stock = Math.round((art.stock - qty) * 1000) / 1000;
    const salePrice = art.sellPrice || art.price || 0;
    const costPrice = art.price || 0;
    const saleTotal = salePrice * qty;
    const profit    = (salePrice - costPrice) * qty;
    const pmSel = $('sale-payment');
    const payMethod = pmSel ? pmSel.value : 'cash';
    const { clientId, clientName } = _resolveClientForSale();
    S.sales.unshift({ id: Date.now(), productId: art.id, productName: art.name, qty, total: saleTotal, profit, date: new Date().toISOString(), paymentMethod: payMethod, clientId, clientName });
    localStorage.setItem('baro_articles', JSON.stringify(S.articles));
    logActivity('sale', `${art.name} x${qty} — ${fmt(saleTotal)} ${sym()}`);
    showToast(`${t('saleConfirmed')} — ${fmt(saleTotal)} ${sym()}`);
    render();
    return;
  }

  // ── Mode transformateur : vente de produits composés ──
  const product = S.products.find(p => p.id === parseInt(sel.value));
  if (!product) return;
  const qty = Math.max(1, parseInt(qtyEl.value) || 1);
  for (const comp of product.composition) {
    const art = S.articles.find(a => a.id === comp.id);
    if (!art || art.stock < comp.qty * qty) {
      showToast(`Stock insuffisant : ${art ? art.name : '?'}`, 'error');
      return;
    }
  }
  product.composition.forEach(comp => {
    const art = S.articles.find(a => a.id === comp.id);
    if (art) art.stock = Math.round((art.stock - comp.qty * qty) * 10) / 10;
  });
  let saleTotal = product.price * qty;
  const saleCost = (product.purchasePrice || 0) * qty;
  const pmSel = $('sale-payment');
  const payMethod = pmSel ? pmSel.value : 'cash';
  const { clientId, clientName } = _resolveClientForSale();
  const PMLABELS = {cash:'Especes',wave:'Wave',orange:'Orange Money',moov:'Moov Money',mtn:'MTN MoMo'};
  // Apply promo
  const promo = _getActivePromo(product.id);
  let promoName = null, promoDiscount = 0;
  if (promo) { promoDiscount = promo.discount; promoName = promo.name; saleTotal = Math.round(saleTotal * (100 - promoDiscount) / 100); }
  const __sale = { id: Date.now(), productId: product.id, productName: product.name, qty, total: saleTotal, profit: saleTotal - saleCost, date: new Date().toISOString(), paymentMethod: payMethod, clientId, clientName: client?.name || clientName || null, promoName, promoDiscount };
  S.sales.unshift(__sale);
  // Hooks intégrations temps réel
  try { if (typeof sheetsAutoAppendSale === 'function') sheetsAutoAppendSale(__sale); } catch(_){}
  try { if (typeof posAutoPrintSale === 'function') posAutoPrintSale(__sale); } catch(_){}
  try { if (typeof comptaAutoPushSale === 'function') comptaAutoPushSale(__sale); } catch(_){}
  try { if (typeof triggerWhatsAppAuto === 'function' && client?.phone) triggerWhatsAppAuto('sale', { phone: client.phone, product:product.name, qty, total:saleTotal, client:client.name }); } catch(_){}
  // Loyalty points (with tier multiplier)
  if (S.loyaltyConfig?.enabled && clientId) {
    const cl = S.clients.find(c => c.id === clientId);
    if (cl) {
      const tier = _getClientTier(cl);
      const mult = tier?.multiplier || 1;
      const pts = Math.floor(saleTotal * (S.loyaltyConfig.pointsPerFcfa || 1) * mult);
      cl.loyaltyPoints = (cl.loyaltyPoints || 0) + pts;
      localStorage.setItem('baro_clients', JSON.stringify(S.clients));
      // Check tier upgrade
      const newTier = _getClientTier(cl);
      if (newTier && tier && newTier.id !== tier.id && newTier.min > tier.min) {
        showToast(`🎉 ${cl.name} a atteint le palier ${newTier.name} ${newTier.icon||''} !`, 'success');
      }
    }
  }
  // Attribution au membre connecté
  const __currentMember = (typeof getCurrentMember === 'function') ? getCurrentMember() : null;
  if (__currentMember) {
    __sale.memberId = __currentMember.id;
    __sale.memberName = __currentMember.name;
  }
  logActivity('sale', `${product.name} x${qty} — ${fmt(saleTotal)} ${sym()} (${PMLABELS[payMethod]||payMethod})`);
  if (typeof logAudit === 'function') logAudit('sale', 'create', { product: product.name, qty, total: saleTotal });
  showToast(`${t('saleConfirmed')} — ${fmt(saleTotal)} ${sym()}`);
  render();
}

async function saveArticle() {
  const f = S.form;
  if (!f.name.trim()) { showToast(t('nameRequired'), 'error'); return; }
  const bt = (typeof getBusinessType === 'function') ? getBusinessType() : 'maker';
  const price = parseFloat(f.price) || 0;
  const purchasePrice = parseFloat(f.purchasePrice) || 0;
  // Validation revendeur : prix d'achat recommandé
  if (bt === 'reseller' && price > 0 && purchasePrice > 0 && purchasePrice >= price) {
    if (!confirm(`⚠️ Le prix d'achat (${purchasePrice} FCFA) est ≥ au prix de vente (${price} FCFA).\nVous perdrez de l'argent sur chaque vente.\n\nContinuer quand même ?`)) return;
  }
  try {
    const data = await api('POST', '/api/articles/', {
      name:            f.name.trim(),
      quantity:        parseFloat(f.stock) || 0,
      unit:            f.unit || 'pcs',
      alert_threshold: parseFloat(f.min) || null,
      lead_time_days:  parseInt(f.lead) || 7,
      ref:             f.ref || null,
      price:           price,
      purchase_price:  purchasePrice,
      sell_price:      parseFloat(f.sellPrice) || 0,
      category:        f.category || '',
    });
    const newArt = articleFromAPI(data);
    newArt.ref = f.ref || '';
    newArt.price = price;
    newArt.purchasePrice = purchasePrice;
    newArt.sellPrice = parseFloat(f.sellPrice) || 0;
    newArt.category = f.category || '';
    newArt.perishable = !!f.perishable;
    newArt.expiry = (f.perishable ? f.expiry : '') || f.expiry || '';
    newArt.image = f.image || '';
    newArt.ean = (f.ean || '').trim();
    newArt.barcode = newArt.ean;
    S.articles.push(newArt);
    localStorage.setItem('baro_articles', JSON.stringify(S.articles));
    logActivity('new_article', f.name.trim());
    const msg = bt === 'reseller'
      ? `✅ "${f.name}" ajouté${purchasePrice > 0 && price > 0 ? ` — marge ${Math.round(((price - purchasePrice) / price) * 100)}%` : ''}`
      : `"${f.name}" ${t('added') || 'ajouté'}`;
    showToast(msg);
    S.form = { name:'', stock:0, min:0, unit:'', lead:7, ref:'', price:0, purchasePrice:0, sellPrice:0, expiry:'', perishable:false, category:'', image:'', ean:'' };
    nav('pantry');
  } catch(e) {
    showToast(e.message, 'error');
  }
}

async function saveProduct() {
  const nameEl  = $('prod-name');
  const priceEl = $('prod-price');
  if (!nameEl || !nameEl.value.trim()) { showToast(t('nameRequired'), 'error'); return; }
  const composition = [];
  document.querySelectorAll('.comp-input').forEach(row => {
    const artId = parseInt(row.dataset.id);
    const art   = S.articles.find(a => a.id === artId);
    const qtyEl = row.querySelector('.comp-qty');
    const rawQty = parseFloat(qtyEl?.value) || 0;
    if (rawQty > 0 && art) {
      const selUnit   = S.compUnits[artId] || art.unit;
      const converted = convertQty(rawQty, selUnit, art.unit);
      composition.push({ article_id: artId, quantity_used: converted });
    }
  });
  try {
    const costEl = $('prod-cost');
    const data = await api('POST', '/api/products/', {
      name:           nameEl.value.trim(),
      purchase_price: parseFloat(costEl?.value) || 0,
      price:          parseFloat(priceEl?.value) || 0,
      composition
    });
    S.products.push(productFromAPI(data));
    try { localStorage.setItem('stockr_products', JSON.stringify(S.products)); } catch(_){}
    recalcAllMins();
    if (typeof logAudit === 'function') logAudit('product', 'create', { name: nameEl.value });
    showToast(`Produit "${nameEl.value}" créé`);
    nav('products');
  } catch(e) {
    showToast(e.message, 'error');
  }
}

// ── Export CSV ────────────────────────────────
function downloadCSV(filename, rows) {
  const BOM = '\uFEFF';
  const csv = BOM + rows.map(r => r.map(c => `"${String(c).replace(/"/g,'""')}"`).join(',')).join('\n');
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = filename; a.click();
  URL.revokeObjectURL(url);
  showToast(`${filename} téléchargé`);
}

// En-tête CSV pro : raison sociale, coordonnées, date, résumé
function _csvHeader(title, summary = []) {
  const biz = S.session?.business || S.session?.name || 'BARO Commerce';
  const now = new Date();
  const dateStr = now.toLocaleDateString('fr-FR', { day:'2-digit', month:'long', year:'numeric' });
  const timeStr = now.toLocaleTimeString('fr-FR', { hour:'2-digit', minute:'2-digit' });
  const rows = [
    ['═══════════════════════════════════════'],
    [biz.toUpperCase()],
    [title],
    ['═══════════════════════════════════════'],
    ['Généré le', dateStr + ' à ' + timeStr],
    ['Email', S.session?.email || ''],
    ['Téléphone', S.session?.phone || ''],
    ['Devise', S.session?.currency_symbol || 'FCFA'],
  ];
  if (S.session?.rccm) rows.push(['RCCM', S.session.rccm]);
  if (S.session?.ncc) rows.push(['CC Fiscal', S.session.ncc]);
  summary.forEach(([k,v]) => rows.push([k, v]));
  rows.push([''], [''], ['--- DONNÉES ---'], ['']);
  return rows;
}

function exportArticlesCSV() {
  const totalVal = S.articles.reduce((s,a)=>s+(a.stock||0)*(a.purchasePrice||a.price||0), 0);
  const lowStock = S.articles.filter(a => a.stock < (a.min||0) && (a.min||0) > 0).length;
  const rows = _csvHeader('📦 INVENTAIRE STOCK', [
    ['Nombre articles', S.articles.length],
    ['Stock faible', lowStock],
    ['Valeur totale stock', fmt(totalVal) + ' ' + sym()],
  ]);
  rows.push(['#', 'Nom article', 'Référence', 'Stock', 'Unité', 'Seuil alerte', 'Prix achat', 'Prix vente', 'Valeur stock', 'Délai (j)', 'Date expiration']);
  S.articles.forEach((a,i) => rows.push([
    i+1, a.name, a.ref || '', a.stock, a.unit, a.min || 0,
    a.purchasePrice || 0, a.price || 0,
    (a.stock||0) * (a.purchasePrice||a.price||0),
    a.lead || 7, a.expiry || ''
  ]));
  rows.push(['', '', '', '', '', '', '', 'TOTAL', totalVal + ' ' + sym()]);
  downloadCSV(`baro_inventaire_${new Date().toISOString().slice(0,10)}.csv`, rows);
}

function exportProductsCSV() {
  const avgMargin = S.products.length ? Math.round(S.products.reduce((s,p)=>s+marginPct(p),0) / S.products.length) : 0;
  const rows = _csvHeader('🏷️ PRODUITS FINIS', [
    ['Nombre produits', S.products.length],
    ['Marge moyenne', avgMargin + '%'],
  ]);
  rows.push(['#', 'Nom produit', 'Prix achat', 'Prix vente', 'Marge %', 'Bénéfice unitaire', 'Dispo max', 'Composition']);
  S.products.forEach((p,i) => {
    const comp = p.composition.map(c => {
      const a = S.articles.find(a => a.id === c.id);
      return a ? `${c.qty} ${a.unit} ${a.name}` : '';
    }).filter(Boolean).join(' + ');
    rows.push([i+1, p.name, p.purchasePrice || 0, p.price, marginPct(p) + '%', profitUnit(p), productMaxMake(p), comp]);
  });
  downloadCSV(`baro_produits_${new Date().toISOString().slice(0,10)}.csv`, rows);
}

function exportSalesCSV() {
  const totalCA = S.sales.reduce((s,v)=>s+v.total,0);
  const totalProfit = S.sales.reduce((s,v)=>s+(v.profit||0),0);
  const avgBasket = S.sales.length ? Math.round(totalCA / S.sales.length) : 0;
  const avgMargin = totalCA ? Math.round(totalProfit / totalCA * 100) : 0;
  const rows = _csvHeader('💰 HISTORIQUE VENTES', [
    ['Nombre ventes', S.sales.length],
    ['Chiffre d\'affaires', fmt(totalCA) + ' ' + sym()],
    ['Bénéfice total', fmt(totalProfit) + ' ' + sym()],
    ['Panier moyen', fmt(avgBasket) + ' ' + sym()],
    ['Marge globale', avgMargin + '%'],
  ]);
  rows.push(['#', 'Date', 'Heure', 'N° Facture', 'Produit', 'Quantité', 'Prix unitaire', 'Total', 'Bénéfice', 'Client', 'Paiement', 'Promo', 'Statut']);
  S.sales.forEach((s,i) => {
    const d = new Date(s.date);
    const unit = s.qty > 0 ? Math.round(s.total / s.qty) : 0;
    rows.push([
      i+1,
      d.toLocaleDateString('fr-FR'),
      d.toLocaleTimeString('fr-FR', {hour:'2-digit', minute:'2-digit'}),
      _invNum ? _invNum(s.id) : ('INV-'+s.id),
      s.productName, s.qty, unit, s.total, s.profit || 0,
      s.clientName || 'Anonyme',
      s.paymentMethod || 'cash',
      s.promoName || '',
      'Validée'
    ]);
  });
  rows.push([], ['', '', '', '', '', 'TOTAUX', '', totalCA + ' ' + sym(), totalProfit + ' ' + sym()]);
  downloadCSV(`baro_ventes_${new Date().toISOString().slice(0,10)}.csv`, rows);
}

function exportAllCSV() {
  exportArticlesCSV();
  setTimeout(() => exportProductsCSV(), 300);
  setTimeout(() => exportSalesCSV(), 600);
}

// ── EXCEL XLSX (format HTML-as-XLS, ouvrable par Excel, LibreOffice, Numbers) ──
function _xlsEscape(v) {
  if (v === null || v === undefined) return '';
  return String(v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}
function _buildXlsSheet(title, headers, rows, meta = {}) {
  const header = `<tr style="background:#4F46E5;color:#fff;font-weight:bold">${headers.map(h => `<th style="padding:6px 8px;border:1px solid #333">${_xlsEscape(h)}</th>`).join('')}</tr>`;
  const body = rows.map((r,i) => `<tr style="${i%2?'background:#F9FAFB':''}">${r.map(c => {
    const n = Number(c);
    const isNum = !isNaN(n) && String(c).trim() !== '' && /^-?\d+(\.\d+)?$/.test(String(c).trim());
    return `<td style="padding:4px 8px;border:1px solid #D1D5DB${isNum?';text-align:right':''}">${_xlsEscape(c)}</td>`;
  }).join('')}</tr>`).join('');
  const footer = meta.totalRow ? `<tr style="background:#E0E7FF;font-weight:bold"><td colspan="${headers.length-1}" style="padding:6px 8px;border:1px solid #333">TOTAL</td><td style="padding:6px 8px;border:1px solid #333;text-align:right">${_xlsEscape(meta.totalRow)}</td></tr>` : '';
  return `<h2 style="font-family:Arial;color:#4F46E5">${_xlsEscape(title)}</h2><table border="1" cellspacing="0" style="border-collapse:collapse;font-family:Arial;font-size:11px">${header}${body}${footer}</table><br/>`;
}
function downloadXLSX(filename, sheets) {
  const html = `<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40"><head><meta charset="UTF-8"><!--[if gte mso 9]><xml><x:ExcelWorkbook><x:ExcelWorksheets><x:ExcelWorksheet><x:Name>${filename.replace('.xls','')}</x:Name><x:WorksheetOptions><x:DisplayGridlines/></x:WorksheetOptions></x:ExcelWorksheet></x:ExcelWorksheets></x:ExcelWorkbook></xml><![endif]--></head><body>${sheets}</body></html>`;
  const blob = new Blob(['\uFEFF' + html], { type: 'application/vnd.ms-excel;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = filename; a.click();
  URL.revokeObjectURL(url);
  showToast(`${filename} téléchargé`);
}
function exportArticlesXLSX() {
  const rows = S.articles.map(a => [a.name, a.ref||'', a.stock, a.unit, a.min||0, a.lead||7, a.price||0, a.expiry||'']);
  const sheet = _buildXlsSheet('Articles / Stock', ['Nom','Référence','Stock','Unité','Seuil min','Délai (j)','Prix ('+sym()+')','Expiration'], rows);
  downloadXLSX(`stockr_articles_${new Date().toISOString().slice(0,10)}.xls`, sheet);
}
function exportProductsXLSX() {
  const rows = S.products.map(p => {
    const comp = p.composition.map(c => {
      const a = S.articles.find(a => a.id === c.id);
      return a ? `${c.qty} ${a.unit} ${a.name}` : '';
    }).filter(Boolean).join(' + ');
    return [p.name, p.purchasePrice||0, p.price, marginPct(p)+'%', profitUnit(p), productMaxMake(p), comp];
  });
  const sheet = _buildXlsSheet('Produits finis', ['Nom','Coût ('+sym()+')','Prix vente ('+sym()+')','Marge %','Bénéfice/u','Dispo','Composition'], rows);
  downloadXLSX(`stockr_produits_${new Date().toISOString().slice(0,10)}.xls`, sheet);
}
function exportSalesXLSX() {
  const rows = S.sales.map(s => [
    fmtDate(s.date), s.productName, s.qty, s.total, s.profit||0,
    s.clientName || '', s.paymentMethod || 'cash', s.promoName || ''
  ]);
  const total = S.sales.reduce((sum,s)=>sum+s.total, 0);
  const sheet = _buildXlsSheet('Historique des ventes', ['Date','Produit','Qté','Total ('+sym()+')','Bénéfice','Client','Paiement','Promo'], rows, { totalRow: fmt(total)+' '+sym() });
  downloadXLSX(`stockr_ventes_${new Date().toISOString().slice(0,10)}.xls`, sheet);
}
function exportClientsXLSX() {
  const rows = (S.clients||[]).map(c => {
    const spent = S.sales.filter(s=>s.clientId===c.id).reduce((sum,s)=>sum+s.total, 0);
    const orders = S.sales.filter(s=>s.clientId===c.id).length;
    return [c.name, c.phone||'', c.email||'', c.address||'', orders, spent, c.loyaltyPoints||0, fmtDate(c.createdAt||new Date().toISOString())];
  });
  const sheet = _buildXlsSheet('Clients', ['Nom','Téléphone','Email','Adresse','Commandes','Total dépensé ('+sym()+')','Points fidélité','Date création'], rows);
  downloadXLSX(`stockr_clients_${new Date().toISOString().slice(0,10)}.xls`, sheet);
}
function exportFullXLSX() {
  // Dashboard d'abord (résumé avec KPI)
  const now = new Date();
  const today = now.toISOString().slice(0,10);
  const monthAgo = new Date(now.getTime() - 30*86400000).toISOString().slice(0,10);
  const totalCA = S.sales.reduce((s,v)=>s+v.total,0);
  const totalProfit = S.sales.reduce((s,v)=>s+(v.profit||0),0);
  const totalStock = S.articles.reduce((s,a)=>s+(a.stock||0)*(a.purchasePrice||a.price||0),0);
  const caMonth = S.sales.filter(s => s.date >= monthAgo).reduce((sum,v)=>sum+v.total,0);
  const caToday = S.sales.filter(s => (s.date||'').slice(0,10) === today).reduce((sum,v)=>sum+v.total,0);
  const topProducts = Object.entries(S.sales.reduce((m,s)=>{m[s.productName]=(m[s.productName]||0)+s.total;return m;},{}))
    .sort((a,b)=>b[1]-a[1]).slice(0,10);
  const dashHdr = `<h2 style="color:#10b981;font-family:Arial">📊 TABLEAU DE BORD — ${S.session?.business||'BARO'}</h2><p>Généré le ${now.toLocaleString('fr-FR')}</p>`;
  const dashRows = [
    ['INDICATEUR', 'VALEUR', 'UNITÉ'],
    ['CA total', totalCA, sym()],
    ['CA 30 jours', caMonth, sym()],
    ['CA aujourd\'hui', caToday, sym()],
    ['Bénéfice total', totalProfit, sym()],
    ['Marge moyenne', totalCA ? Math.round(100*totalProfit/totalCA)+'%' : '0%', ''],
    ['Nb ventes', S.sales.length, ''],
    ['Panier moyen', S.sales.length ? Math.round(totalCA/S.sales.length) : 0, sym()],
    ['Valeur stock', Math.round(totalStock), sym()],
    ['Nb articles', S.articles.length, ''],
    ['Nb produits', S.products.length, ''],
    ['Nb clients', (S.clients||[]).length, ''],
    ['Nb packs actifs', (S.packs||[]).filter(p=>p.active!==false).length, ''],
  ];
  const dashSheet = _buildXlsSheet('📊 Tableau de bord', ['Indicateur','Valeur','Unité'], dashRows.slice(1));

  // Top 10 produits
  const topSheet = _buildXlsSheet('🏆 Top 10 produits', ['Rang','Produit','CA ('+sym()+')'],
    topProducts.map((e,i) => [i+1, e[0], e[1]]));

  const s1 = _buildXlsSheet('📦 Articles / Stock',
    ['Nom','Référence','Stock','Unité','Seuil min','Prix achat','Prix vente','Valeur stock'],
    S.articles.map(a => [
      a.name, a.ref||'', a.stock, a.unit, a.min||0,
      a.purchasePrice||0, a.price||0,
      (a.stock||0)*(a.purchasePrice||a.price||0)
    ]));
  const s2 = _buildXlsSheet('🏷️ Produits finis',
    ['Nom','Coût','Prix vente','Marge FCFA','Marge %','Dispo','CA généré'],
    S.products.map(p => {
      const caProd = S.sales.filter(s=>s.productId===p.id).reduce((sum,v)=>sum+v.total,0);
      return [p.name, p.purchasePrice||0, p.price, p.price-(p.purchasePrice||0), marginPct(p)+'%', productMaxMake(p), caProd];
    }));
  const s3 = _buildXlsSheet('💰 Ventes',
    ['Date','Produit','Qté','Total','Bénéfice','Client','Paiement','Promo'],
    S.sales.map(s => [fmtDate(s.date), s.productName, s.qty, s.total, s.profit||0, s.clientName||'', s.paymentMethod||'cash', s.promoName||'']),
    { totalRow: fmt(totalCA)+' '+sym() });
  const s4 = _buildXlsSheet('👥 Clients',
    ['Nom','Téléphone','Email','Commandes','Total dépensé','Points fidélité'],
    (S.clients||[]).map(c => {
      const spent = S.sales.filter(s=>s.clientId===c.id).reduce((sum,v)=>sum+v.total,0);
      const orders = S.sales.filter(s=>s.clientId===c.id).length;
      return [c.name, c.phone||'', c.email||'', orders, spent, c.loyaltyPoints||0];
    }));
  const s5 = _buildXlsSheet('📦 Packs',
    ['Nom','Nb produits','Prix original','Prix final','Économie','Dispo','Actif'],
    (S.packs||[]).map(pk => [pk.name, pk.items?.length||0, packOriginalPrice(pk), packFinalPrice(pk), packSavings(pk), packMaxAvailable(pk), pk.active!==false?'Oui':'Non']));
  // Journal ventes 30 derniers jours (agrégé par jour)
  const dayAgg = {};
  S.sales.filter(s => s.date >= monthAgo).forEach(s => {
    const d = (s.date||'').slice(0,10);
    if (!dayAgg[d]) dayAgg[d] = { ca:0, profit:0, count:0 };
    dayAgg[d].ca += s.total;
    dayAgg[d].profit += (s.profit||0);
    dayAgg[d].count += 1;
  });
  const s6 = _buildXlsSheet('📅 Journal 30 jours',
    ['Date','CA','Bénéfice','Nb ventes','Panier moyen'],
    Object.entries(dayAgg).sort((a,b)=>b[0].localeCompare(a[0])).map(([d,v]) => [d, v.ca, v.profit, v.count, v.count ? Math.round(v.ca/v.count) : 0]));

  downloadXLSX(`stockr_export_complet_${today}.xls`, dashSheet + topSheet + s1 + s2 + s3 + s4 + s5 + s6);
  showToast('📊 Export complet : 8 feuilles Excel', 'success');
}

// ── PDF CHART HELPERS (natifs jsPDF, pas d'html2canvas) ────────
function _pdfBarChart(doc, { data, x, y, w, h, title, color = [16,185,129], maxLabel = 10 }) {
  // data: [{ label, value }]
  if (!data?.length) return;
  const max = Math.max(...data.map(d => d.value), 1);
  const padTop = title ? 10 : 4;
  const padBottom = 14; // labels
  const chartH = h - padTop - padBottom;
  const chartY = y + padTop;
  // Title
  if (title) {
    doc.setFontSize(10); doc.setFont('helvetica','bold'); doc.setTextColor(30,30,30);
    doc.text(title, x, y + 5);
  }
  // Frame
  doc.setDrawColor(220,220,220); doc.setLineWidth(0.2);
  doc.line(x, chartY + chartH, x + w, chartY + chartH); // x axis
  doc.line(x, chartY, x, chartY + chartH); // y axis
  // Grid (4 lines)
  doc.setDrawColor(240,240,240);
  for (let i=1; i<=3; i++) {
    const gy = chartY + chartH - (i * chartH / 4);
    doc.line(x, gy, x + w, gy);
  }
  // Bars
  const barGap = 1;
  const barW = Math.max(1, (w - (data.length + 1) * barGap) / data.length);
  data.forEach((d, i) => {
    const bh = Math.max(0.3, (d.value / max) * chartH);
    const bx = x + barGap + i * (barW + barGap);
    const by = chartY + chartH - bh;
    doc.setFillColor(color[0], color[1], color[2]);
    doc.rect(bx, by, barW, bh, 'F');
    // Value on top (only if room)
    if (data.length <= 15) {
      doc.setFontSize(6); doc.setTextColor(60,60,60); doc.setFont('helvetica','normal');
      doc.text(String(d.value >= 1000 ? Math.round(d.value/1000)+'k' : d.value), bx + barW/2, by - 1, { align:'center' });
    }
    // Label under
    if (data.length <= maxLabel) {
      doc.setFontSize(6); doc.setTextColor(100,100,100);
      doc.text(String(d.label).slice(0,8), bx + barW/2, chartY + chartH + 4, { align:'center' });
    }
  });
  // Y-axis scale (max label)
  doc.setFontSize(6); doc.setTextColor(120,120,120);
  doc.text(String(max >= 1000 ? Math.round(max/1000)+'k' : max), x - 1, chartY + 2, { align:'right' });
}

function _pdfPieChart(doc, { data, cx, cy, r, title }) {
  // data: [{ label, value, color:[r,g,b] }]
  if (!data?.length) return;
  const total = data.reduce((s,d) => s + d.value, 0) || 1;
  if (title) {
    doc.setFontSize(10); doc.setFont('helvetica','bold'); doc.setTextColor(30,30,30);
    doc.text(title, cx - r, cy - r - 3);
  }
  let startAngle = -Math.PI / 2; // start at top
  data.forEach(d => {
    const slice = (d.value / total) * Math.PI * 2;
    const endAngle = startAngle + slice;
    doc.setFillColor(d.color[0], d.color[1], d.color[2]);
    // Approximate pie with triangles fan
    const segs = Math.max(12, Math.round(slice * 30));
    for (let i = 0; i < segs; i++) {
      const a1 = startAngle + (i * slice / segs);
      const a2 = startAngle + ((i + 1) * slice / segs);
      doc.triangle(cx, cy, cx + r * Math.cos(a1), cy + r * Math.sin(a1), cx + r * Math.cos(a2), cy + r * Math.sin(a2), 'F');
    }
    startAngle = endAngle;
  });
  // Legend
  let ly = cy + r + 5;
  doc.setFontSize(7); doc.setFont('helvetica','normal');
  data.forEach(d => {
    doc.setFillColor(d.color[0], d.color[1], d.color[2]);
    doc.rect(cx - r, ly - 2, 3, 3, 'F');
    doc.setTextColor(60,60,60);
    const pct = Math.round(100 * d.value / total);
    doc.text(`${d.label} — ${pct}%`, cx - r + 5, ly);
    ly += 4;
  });
}

// ── RAPPORT PDF GLOBAL ────────────────────────
function generateStockReportPDF() {
  if (typeof window.jspdf === 'undefined') { showToast('jsPDF indisponible', 'error'); return; }
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ unit:'mm', format:'a4' });
  const biz = S.session?.business || S.session?.name || 'Mon Commerce';
  const date = new Date().toLocaleDateString('fr-FR', { day:'numeric', month:'long', year:'numeric' });
  // Header
  doc.setFillColor(79,70,229); doc.rect(0,0,210,32,'F');
  doc.setTextColor(255,255,255); doc.setFontSize(20); doc.setFont('helvetica','bold');
  doc.text('RAPPORT DE STOCK', 16, 15);
  doc.setFontSize(10); doc.setFont('helvetica','normal');
  doc.text(biz + ' · ' + date, 16, 23);
  // Stats
  let y = 42;
  const total = S.articles.length;
  const outOfStock = S.articles.filter(a => a.stock === 0).length;
  const lowStock = S.articles.filter(a => a.stock > 0 && a.min > 0 && a.stock < a.min).length;
  const stockValue = S.articles.reduce((s,a) => s + (a.stock||0) * (a.purchasePrice||0), 0);
  doc.setTextColor(30,30,30); doc.setFontSize(9);
  doc.text(`Total articles : ${total}   ·   Ruptures : ${outOfStock}   ·   Stock bas : ${lowStock}   ·   Valeur stock : ${fmt(stockValue)} ${sym()}`, 16, y);
  y += 10;
  // En-tête tableau
  doc.setFillColor(79,70,229); doc.rect(16, y-5, 178, 9, 'F');
  doc.setTextColor(255,255,255); doc.setFont('helvetica','bold'); doc.setFontSize(9);
  doc.text('ARTICLE', 20, y);
  doc.text('STOCK', 120, y, { align:'center' });
  doc.text('SEUIL', 145, y, { align:'center' });
  doc.text('VALEUR', 190, y, { align:'right' });
  y += 8;
  doc.setFont('helvetica','normal'); doc.setTextColor(30,30,30);
  S.articles.slice(0, 40).forEach((a,i) => {
    if (y > 265) { doc.addPage(); y = 20; }
    if (i%2===1) { doc.setFillColor(249,250,251); doc.rect(16, y-5, 178, 8, 'F'); }
    const st = a.stock === 0 ? 'danger' : (a.min && a.stock < a.min ? 'warning' : 'ok');
    doc.text(a.name.slice(0, 44), 20, y);
    if (st === 'danger') doc.setTextColor(220,38,38);
    else if (st === 'warning') doc.setTextColor(180,83,9);
    doc.text(`${fmtQty(a.stock)} ${a.unit||''}`, 120, y, { align:'center' });
    doc.setTextColor(30,30,30);
    doc.text(String(a.min || '—'), 145, y, { align:'center' });
    doc.text(fmt((a.stock||0) * (a.purchasePrice||0)) + ' ' + sym(), 190, y, { align:'right' });
    y += 7;
  });
  if (S.articles.length > 40) {
    doc.setFontSize(8); doc.setTextColor(100,100,100);
    doc.text(`+ ${S.articles.length - 40} autres articles non affichés…`, 105, y+5, { align:'center' });
  }
  // Footer
  doc.setFontSize(8); doc.setTextColor(100,100,100);
  doc.text('Généré par BARO · ' + date, 105, 288, { align:'center' });
  doc.save(`rapport_stock_${new Date().toISOString().slice(0,10)}.pdf`);
  showToast('Rapport PDF généré');
}

function generateSalesReportPDF(period = 'all') {
  if (typeof window.jspdf === 'undefined') { showToast('jsPDF indisponible', 'error'); return; }
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ unit:'mm', format:'a4' });
  const biz = S.session?.business || S.session?.name || 'Mon Commerce';
  const date = new Date().toLocaleDateString('fr-FR', { day:'numeric', month:'long', year:'numeric' });
  const perLabel = {all:'Global', today:"Aujourd'hui", week:'7 derniers jours', month:'30 derniers jours'}[period] || 'Global';
  // Filter
  let sales = S.sales.slice();
  const now = Date.now();
  if (period === 'today') sales = sales.filter(s => new Date(s.date).toDateString() === new Date().toDateString());
  else if (period === 'week') sales = sales.filter(s => now - new Date(s.date).getTime() < 7*86400000);
  else if (period === 'month') sales = sales.filter(s => now - new Date(s.date).getTime() < 30*86400000);
  // Header
  doc.setFillColor(16,185,129); doc.rect(0,0,210,32,'F');
  doc.setTextColor(255,255,255); doc.setFontSize(20); doc.setFont('helvetica','bold');
  doc.text('RAPPORT DES VENTES', 16, 15);
  doc.setFontSize(10); doc.setFont('helvetica','normal');
  doc.text(biz + ' · ' + perLabel + ' · ' + date, 16, 23);
  // Stats
  let y = 42;
  const total = sales.reduce((s,v) => s + v.total, 0);
  const profit = sales.reduce((s,v) => s + (v.profit||0), 0);
  const count = sales.length;
  const avgTicket = count ? Math.round(total / count) : 0;
  // Stat cards
  const cards = [
    { label:'Ventes', val: count + ' opérations', color:[79,70,229] },
    { label:'CA', val: fmt(total) + ' ' + sym(), color:[16,185,129] },
    { label:'Bénéfice', val: fmt(profit) + ' ' + sym(), color:[245,158,11] },
    { label:'Panier moyen', val: fmt(avgTicket) + ' ' + sym(), color:[139,92,246] },
  ];
  cards.forEach((c,i) => {
    const x = 16 + i*46;
    doc.setFillColor(c.color[0], c.color[1], c.color[2]);
    doc.roundedRect(x, y, 42, 20, 2, 2, 'F');
    doc.setTextColor(255,255,255); doc.setFontSize(7); doc.setFont('helvetica','normal');
    doc.text(c.label, x+3, y+5);
    doc.setFontSize(10); doc.setFont('helvetica','bold');
    doc.text(c.val, x+3, y+13);
  });
  y += 28;
  // CHART : Évolution 14 jours (ou période sélectionnée)
  const days = period === 'today' ? 1 : period === 'week' ? 7 : period === 'month' ? 30 : 14;
  const trend = [];
  for (let i = days - 1; i >= 0; i--) {
    const d = new Date(); d.setDate(d.getDate() - i);
    const key = d.toISOString().slice(0,10);
    const total = sales.filter(s => (s.date||'').slice(0,10) === key).reduce((sum,s) => sum + s.total, 0);
    trend.push({ label: String(d.getDate()), value: Math.round(total) });
  }
  _pdfBarChart(doc, { data: trend, x: 16, y, w: 178, h: 40, title: `Évolution du CA sur ${days} jours`, color:[16,185,129], maxLabel: 30 });
  y += 48;
  // PIE : répartition par moyen de paiement
  const byPayment = {};
  sales.forEach(s => {
    const pm = s.paymentMethod || 'cash';
    byPayment[pm] = (byPayment[pm] || 0) + s.total;
  });
  const palette = [[16,185,129],[79,70,229],[245,158,11],[139,92,246],[239,68,68],[14,165,233]];
  const pieData = Object.entries(byPayment).map(([k,v], i) => ({ label:k, value:v, color:palette[i % palette.length] }));
  if (pieData.length) {
    _pdfPieChart(doc, { data: pieData, cx: 50, cy: y + 20, r: 18, title: 'Paiement' });
  }
  // Top 5 products
  const byProduct = {};
  sales.forEach(s => {
    if (!byProduct[s.productName]) byProduct[s.productName] = { qty:0, total:0 };
    byProduct[s.productName].qty += s.qty;
    byProduct[s.productName].total += s.total;
  });
  const top5 = Object.entries(byProduct).sort((a,b) => b[1].total - a[1].total).slice(0, 5);
  if (top5.length) {
    doc.setTextColor(30,30,30); doc.setFontSize(12); doc.setFont('helvetica','bold');
    doc.text('Top 5 produits', 16, y); y += 7;
    doc.setFont('helvetica','normal'); doc.setFontSize(9);
    top5.forEach((entry, i) => {
      const [name, d] = entry;
      doc.setFillColor(i%2?249:255, 250, 251); doc.rect(16, y-4, 178, 7, 'F');
      doc.text(`${i+1}. ${name.slice(0,50)}`, 20, y);
      doc.text(`${d.qty} u`, 135, y, { align:'center' });
      doc.setFont('helvetica','bold');
      doc.text(fmt(d.total) + ' ' + sym(), 190, y, { align:'right' });
      doc.setFont('helvetica','normal');
      y += 7;
    });
    y += 6;
  }
  // Ventes récentes
  doc.setTextColor(30,30,30); doc.setFontSize(12); doc.setFont('helvetica','bold');
  doc.text('Ventes récentes', 16, y); y += 7;
  doc.setFillColor(79,70,229); doc.rect(16, y-5, 178, 9, 'F');
  doc.setTextColor(255,255,255); doc.setFontSize(9); doc.setFont('helvetica','bold');
  doc.text('DATE', 20, y);
  doc.text('PRODUIT', 55, y);
  doc.text('QTE', 125, y, { align:'center' });
  doc.text('TOTAL', 190, y, { align:'right' });
  y += 8;
  doc.setFont('helvetica','normal'); doc.setTextColor(30,30,30); doc.setFontSize(8);
  sales.slice(0, 35).forEach((s,i) => {
    if (y > 275) { doc.addPage(); y = 20; }
    if (i%2) { doc.setFillColor(249,250,251); doc.rect(16, y-4, 178, 7, 'F'); }
    doc.text(fmtDate(s.date).slice(0,16), 20, y);
    doc.text(s.productName.slice(0,32), 55, y);
    doc.text(String(s.qty), 125, y, { align:'center' });
    doc.setFont('helvetica','bold');
    doc.text(fmt(s.total) + ' ' + sym(), 190, y, { align:'right' });
    doc.setFont('helvetica','normal');
    y += 7;
  });
  // Footer
  doc.setFontSize(8); doc.setTextColor(100,100,100);
  doc.text('Généré par BARO · ' + date, 105, 288, { align:'center' });
  doc.save(`rapport_ventes_${period}_${new Date().toISOString().slice(0,10)}.pdf`);
  showToast('Rapport PDF généré');
}

