function updateMarginPreview() {
  const cost = parseFloat($('prod-cost')?.value) || 0;
  const price = parseFloat($('prod-price')?.value) || 0;
  const box = document.getElementById('margin-preview');
  const val = document.getElementById('margin-val');
  if (!box || !val) return;
  if (price > 0) {
    const pct = Math.round(((price - cost) / price) * 100);
    const profit = price - cost;
    val.innerHTML = `${pct}% · ${t('profitShort')} ${fmt(profit)} ${sym()}/u`;
    val.style.color = pct >= 20 ? 'var(--success)' : pct >= 0 ? 'var(--warning)' : 'var(--danger)';
    box.style.display = '';
  } else {
    box.style.display = 'none';
  }
}

function toggleCart() {
  S.cartOpen = !S.cartOpen;
  render();
}

async function deleteProduct(id) {
  if (typeof hasPermission === 'function' && !hasPermission('products') && !hasPermission('all')) {
    if (typeof requirePermission === 'function') requirePermission('products');
    return;
  }
  const p = S.products.find(p => p.id === id);
  if (!p) return;
  if (!confirm(`Supprimer "${p.name}" ?`)) return;
  try {
    await api('DELETE', `/api/products/${id}`);
    S.products = S.products.filter(p => p.id !== id);
    if (typeof logAudit === 'function') logAudit('product', 'delete', { name: p.name, id });
    showToast(`"${p.name}" supprimé`);
    render();
  } catch(e) {
    showToast(e.message, 'error');
  }
}

async function saveEditProduct() {
  const nameEl  = $('prod-name');
  const priceEl = $('prod-price');
  if (!nameEl?.value.trim()) { showToast(t('nameRequired'), 'error'); return; }
  const p = S.products.find(p => p.id === S.editProductId);
  if (!p) return;
  const composition = [];
  document.querySelectorAll('.comp-input').forEach(row => {
    const artId = parseInt(row.dataset.id);
    const art   = S.articles.find(a => a.id === artId);
    const qtyEl = row.querySelector('.comp-qty');
    const rawQty = parseFloat(qtyEl?.value) || 0;
    if (rawQty > 0 && art) {
      const selUnit   = S.compUnits[artId] || art.unit;
      const converted = convertQty(rawQty, selUnit, art.unit);
      composition.push({ article_id: artId, quantity_used: converted });
    }
  });
  try {
    const costEl = $('prod-cost');
    const data = await api('PUT', `/api/products/${p.id}`, {
      name:           nameEl.value.trim(),
      purchase_price: parseFloat(costEl?.value) || 0,
      price:          parseFloat(priceEl?.value) || 0,
      composition,
    });
    p.name  = data.name;
    p.price = data.price;
    p.purchasePrice = data.purchase_price || 0;
    p.composition = (data.composition || []).map(c => ({ id: c.article.id, qty: c.quantity_used }));
    recalcAllMins();
    showToast(`"${p.name}" mis à jour`);
    nav('products');
  } catch(e) {
    showToast(e.message, 'error');
  }
}

function toggleAuthPwd(e) {
  if (e) { e.preventDefault(); e.stopPropagation(); }
  S.authShowPwd = !S.authShowPwd;
  // Zéro render() — DOM direct uniquement, les champs ne sont jamais vidés
  const pEl  = document.getElementById('auth-pwd');
  const p2El = document.getElementById('auth-pwd2');
  if (pEl)  pEl.classList.toggle('pwd-masked', !S.authShowPwd);
  if (p2El) p2El.classList.toggle('pwd-masked', !S.authShowPwd);
  document.querySelectorAll('.pwd-eye').forEach(btn => {
    btn.innerHTML = S.authShowPwd ? IC.eyeOff : IC.eye;
  });
}

// ── Cart actions ──────────────────────────────
function addToCart() {
  const sel   = $('sale-product');
  const qtyEl = $('sale-qty');
  if (!sel?.value) { showToast(t('chooseProduct'), 'error'); return; }
  const val = String(sel.value);
  // Handle both prefixed (prod_X / art_X / pack_X) and raw product id — gère aussi le mode revendeur
  let item = null;
  const sellable = bt_sellableItems();
  item = sellable.find(it => it.id === val) || sellable.find(it => String(it.productId||'') === val);
  if (!item && /^\d+$/.test(val)) {
    // backwards compat : pure numeric id means a product
    const product = S.products.find(p => p.id === parseInt(val));
    if (product) item = { id:'prod_'+product.id, productId:product.id, name:product.name, price:product.price, purchasePrice:product.purchasePrice||0, kind:'product' };
  }
  if (!item) return;
  const qty = Math.max(1, parseFloat(qtyEl?.value) || 1);
  const existing = S.cart.find(c => c.cartId === item.id);
  if (existing) { existing.qty += qty; }
  else {
    S.cart.push({
      cartId: item.id,
      kind: item.kind,
      productId: item.productId || null,
      articleId: item.articleId || null,
      productName: item.name,
      qty,
      unitPrice: item.price,
      unitCost: item.purchasePrice,
    });
  }
  showToast(`${item.name} ajouté au panier`);
  render();
}

function removeFromCart(idx) {
  S.cart.splice(idx, 1);
  render();
}

// ── Multi-cart (vente en lot) ─────────────────
function setSaleMode(mode) {
  S.saleMode = mode;
  render();
}
function toggleMultiCart(itemId) {
  if (!S.multiCart) S.multiCart = {};
  if (S.multiCart[itemId]) delete S.multiCart[itemId];
  else S.multiCart[itemId] = 1;
  render();
}
function updateMultiCartQty(itemId, delta) {
  if (!S.multiCart) S.multiCart = {};
  const sellable = bt_sellableItems();
  const it = sellable.find(i => i.id === itemId);
  const max = it ? it.stock : 9999;
  const current = S.multiCart[itemId] || 0;
  const next = Math.max(1, Math.min(max, current + delta));
  S.multiCart[itemId] = next;
  render();
}
function setMultiCartQty(itemId, val) {
  if (!S.multiCart) S.multiCart = {};
  const sellable = bt_sellableItems();
  const it = sellable.find(i => i.id === itemId);
  const max = it ? it.stock : 9999;
  const n = Math.max(1, Math.min(max, parseInt(val) || 1));
  S.multiCart[itemId] = n;
  render();
}
function clearMultiCart() {
  S.multiCart = {};
  render();
}
async function confirmMultiSale() {
  if (!S.multiCart || !Object.keys(S.multiCart).length) { showToast('Panier vide', 'error'); return; }
  const sellable = bt_sellableItems();
  const clientSel = $('multi-client');
  const clientId = clientSel ? parseInt(clientSel.value) || null : null;
  const client = clientId ? S.clients.find(c => c.id === clientId) : null;
  const pmSel = $('multi-payment');
  const payMethod = pmSel ? pmSel.value : 'cash';

  let total = 0, newSales = [];
  for (const [itemId, qty] of Object.entries(S.multiCart)) {
    const it = sellable.find(i => i.id === itemId);
    if (!it) continue;
    let lineTotal = it.price * qty;
    let lineProfit = (it.price - (it.purchasePrice||0)) * qty;
    let promoName = null, promoDiscount = 0;
    if (it.kind === 'product') {
      const promo = _getActivePromo(it.productId);
      if (promo) { promoDiscount = promo.discount; promoName = promo.name; const d = Math.round(lineTotal*promoDiscount/100); lineTotal -= d; lineProfit -= d; }
    }
    try {
      let saleData = null;
      if (it.kind === 'product') {
        try {
          const data = await api('POST', '/api/sales/', { product_id: it.productId, quantity: qty, client_id: clientId, client_name: client?.name || null });
          saleData = data.sale;
        } catch(e) { /* fallback offline */ }
      } else if (it.kind === 'article') {
        // Décrémente directement l'article
        const article = S.articles.find(a => a.id === it.articleId);
        if (article) {
          article.stock = Math.max(0, (article.stock||0) - qty);
          localStorage.setItem('stockr_articles', JSON.stringify(S.articles));
          try { await api('PUT', `/api/articles/${article.id}`, { stock: article.stock }); } catch(e) {}
          S.stockMovements.unshift({ id:Date.now()+Math.random(), articleId:article.id, articleName:article.name, type:'out', qty, reason:'Vente directe', date:new Date().toISOString() });
          localStorage.setItem('stockr_stock_movements', JSON.stringify(S.stockMovements));
        }
      } else if (it.kind === 'pack') {
        // Pack : vendre chaque produit du pack au prorata du pack
        const pack = S.packs.find(p => p.id === it.packId);
        if (pack) {
          for (const comp of (pack.items||[])) {
            try {
              await api('POST', '/api/sales/', { product_id: comp.productId, quantity: (comp.qty||1)*qty, client_id: clientId, client_name: client?.name || null });
            } catch(e) { /* fallback offline */ }
          }
          // Tracer la vente du pack
          S.stockMovements.unshift({ id:Date.now()+Math.random(), type:'out', qty, reason:`Vente pack "${pack.name}"`, date:new Date().toISOString() });
          localStorage.setItem('stockr_stock_movements', JSON.stringify(S.stockMovements));
        }
      }
      const newSale = {
        id: saleData?.id || Date.now() + Math.random(),
        productId: it.productId || null,
        articleId: it.articleId || null,
        packId:    it.packId    || null,
        productName: it.name,
        qty,
        total: lineTotal,
        profit: lineProfit,
        date: saleData?.timestamp || new Date().toISOString(),
        clientId, clientName: client?.name || null,
        paymentMethod: payMethod, promoName, promoDiscount,
        kind: it.kind,
      };
      S.sales.unshift(newSale);
      newSales.push(newSale);
      total += lineTotal;
    } catch(e) { console.warn('sale error', e); }
  }
  localStorage.setItem('stockr_sales', JSON.stringify(S.sales));

  // Loyalty with tier multiplier
  if (S.loyaltyConfig?.enabled && clientId) {
    const cl = S.clients.find(c => c.id === clientId);
    if (cl) {
      const tier = _getClientTier(cl);
      const mult = tier?.multiplier || 1;
      const pts = Math.floor(total * (S.loyaltyConfig.pointsPerFcfa||1) * mult);
      cl.loyaltyPoints = (cl.loyaltyPoints||0) + pts;
      localStorage.setItem('stockr_clients', JSON.stringify(S.clients));
      const newTier = _getClientTier(cl);
      if (newTier && tier && newTier.id !== tier.id && newTier.min > tier.min) {
        showToast(`🎉 ${cl.name} → palier ${newTier.name} ${newTier.icon||''} !`, 'success');
      }
    }
  }
  if (payMethod !== 'cash') {
    S.paymentHistory.unshift({ id:Date.now(), provider:payMethod, amount:total, clientName:client?.name||'Client', date:new Date().toISOString() });
    localStorage.setItem('stockr_payment_history', JSON.stringify(S.paymentHistory));
  }
  logActivity('sale', `Vente multi: ${newSales.length} article(s) — ${fmt(total)} ${sym()}`);
  showToast(`✅ ${newSales.length} articles vendus — ${fmt(total)} ${sym()}`, 'success');
  S.multiCart = {};
  S.multiSearch = '';
  showReceiptBanner(newSales, total);
  render();
}

async function confirmCart() {
  if (!S.cart.length) { showToast(t('emptyCartMsg'), 'error'); return; }
  const { clientId, clientName: resolvedClientName } = _resolveClientForSale();
  const client = clientId ? S.clients.find(c => c.id === clientId) : null;
  const pmSel = $('sale-payment');
  const payMethod = pmSel ? pmSel.value : 'cash';
  try {
    const cartId = 'cart_' + Date.now();
    let total = 0, count = 0, newSales = [];
    for (const item of S.cart) {
      // ── Mode revendeur : déstockage article direct ──
      if (item._reseller) {
        const art = S.articles.find(a => a.id === item._artId);
        if (art) art.stock = Math.round((art.stock - item.qty) * 1000) / 1000;
        const lineTotal  = item.unitPrice * item.qty;
        const lineProfit = (item.unitPrice - (item.unitCost || 0)) * item.qty;
        total += lineTotal; count += item.qty;
        const newSale = { id: Date.now() + Math.random(), cartId, productId: item._artId, productName: item.productName, qty: item.qty, total: lineTotal, profit: lineProfit, date: new Date().toISOString(), clientId, clientName: resolvedClientName || client?.name || null, paymentMethod: payMethod };
        S.sales.unshift(newSale); newSales.push(newSale);
        continue;
      }
      const data = await api('POST', '/api/sales/', { product_id: item.productId, quantity: item.qty, client_id: clientId, client_name: client?.name || null });
      const product = S.products.find(p => p.id === item.productId);
      let lineTotal = (product?.price || 0) * item.qty;
      let lineProfit = ((product?.price || 0) - (product?.purchasePrice || 0)) * item.qty;
      // Apply promo discount
      const promo = _getActivePromo(item.productId);
      let promoName = null, promoDiscount = 0;
      if (promo) {
        promoDiscount = promo.discount;
        promoName = promo.name;
        const discount = Math.round(lineTotal * promoDiscount / 100);
        lineTotal -= discount;
        lineProfit -= discount;
      }
      total += lineTotal;
      count += item.qty;
      const newSale = { id: data.sale.id, cartId, productId: data.sale.product_id, productName: data.sale.product_name, qty: data.sale.quantity, total: lineTotal, profit: lineProfit, date: data.sale.timestamp, clientId, clientName: resolvedClientName || client?.name || null, paymentMethod: payMethod, promoName, promoDiscount };
      S.sales.unshift(newSale);
      newSales.push(newSale);
    }
    // Loyalty points (with tier multiplier)
    if (S.loyaltyConfig?.enabled && clientId) {
      const cl = S.clients.find(c => c.id === clientId);
      if (cl) {
        const tier = _getClientTier(cl);
        const mult = tier?.multiplier || 1;
        const pts = Math.floor(total * (S.loyaltyConfig.pointsPerFcfa || 1) * mult);
        cl.loyaltyPoints = (cl.loyaltyPoints || 0) + pts;
        localStorage.setItem('baro_clients', JSON.stringify(S.clients));
        const newTier = _getClientTier(cl);
        if (newTier && tier && newTier.id !== tier.id && newTier.min > tier.min) {
          showToast(`🎉 ${cl.name} a atteint le palier ${newTier.name} ${newTier.icon||''} !`, 'success');
        }
      }
    }
    // Payment history
    if (payMethod !== 'cash') {
      S.paymentHistory.unshift({ id:Date.now(), provider:payMethod, amount:total, clientName:client?.name||'Client', date:new Date().toISOString() });
      localStorage.setItem('baro_payment_history', JSON.stringify(S.paymentHistory));
    }
    S.cart = [];
    showToast(`${count} ${t('unitsSold')} — ${fmt(total)} ${sym()}`);
    showReceiptBanner(newSales, total);
    // Recharger les articles pour avoir les stocks à jour
    const arts = await api('GET', '/api/articles/');
    S.articles = arts.map(articleFromAPI);
    recalcAllMins();
    render();
  } catch(e) {
    showToast(e.message, 'error');
  }
}

// ── PACKS MANAGEMENT ──────────────────────────
function setProductsTab(tab) {
  S.productsTab = tab;
  render();
}
function resetPackForm() {
  S.packForm = { name:'', description:'', items:[], price:0, discount:0, autoPrice:true, active:true };
  S.editPackId = null;
}
function addPackComponent(productId) {
  if (!S.packForm) resetPackForm();
  productId = parseInt(productId);
  if (!productId) return;
  const existing = S.packForm.items.find(it => it.productId === productId);
  if (existing) { existing.qty = (existing.qty||1) + 1; }
  else { S.packForm.items.push({ productId, qty: 1 }); }
  render();
}
function removePackComponent(productId) {
  if (!S.packForm) return;
  productId = parseInt(productId);
  S.packForm.items = S.packForm.items.filter(it => it.productId !== productId);
  render();
}
function updatePackComponentQty(productId, qty) {
  productId = parseInt(productId);
  const q = Math.max(1, parseInt(qty) || 1);
  const it = S.packForm.items.find(i => i.productId === productId);
  if (it) { it.qty = q; render(); }
}
function updatePackFormField(key, val) {
  if (!S.packForm) resetPackForm();
  if (key === 'autoPrice') S.packForm.autoPrice = !!val;
  else if (key === 'active') S.packForm.active = !!val;
  else if (key === 'discount') S.packForm.discount = Math.max(0, Math.min(100, parseFloat(val)||0));
  else if (key === 'price') S.packForm.price = Math.max(0, parseFloat(val)||0);
  else S.packForm[key] = val;
}
function savePack() {
  const f = S.packForm;
  if (!f?.name?.trim()) { showToast('Nom requis', 'error'); return; }
  if (!f.items?.length) { showToast('Ajoutez au moins un produit', 'error'); return; }
  if (!Array.isArray(S.packs)) S.packs = [];
  if (S.editPackId) {
    const idx = S.packs.findIndex(p => p.id === S.editPackId);
    if (idx >= 0) {
      S.packs[idx] = { ...S.packs[idx], ...f, id: S.editPackId, updatedAt: new Date().toISOString() };
    }
    showToast(`Pack "${f.name}" mis à jour`);
  } else {
    S.packs.unshift({ id: Date.now(), ...f, createdAt: new Date().toISOString() });
    showToast(`Pack "${f.name}" créé`);
    logActivity('pack', `Création pack "${f.name}"`);
  }
  persistPacks();
  resetPackForm();
  S.view = 'products';
  S.productsTab = 'packs';
  render();
}
function editPack(id) {
  const pk = S.packs.find(p => p.id === id);
  if (!pk) return;
  S.editPackId = id;
  S.packForm = {
    name: pk.name || '',
    description: pk.description || '',
    items: (pk.items||[]).map(it => ({ ...it })),
    price: pk.price || 0,
    discount: pk.discount || 0,
    autoPrice: pk.autoPrice !== false,
    active: pk.active !== false,
  };
  S.view = 'pack-form';
  render();
}
function deletePack(id) {
  const pk = S.packs.find(p => p.id === id);
  if (!pk) return;
  if (!confirm(`Supprimer le pack "${pk.name}" ?`)) return;
  S.packs = S.packs.filter(p => p.id !== id);
  persistPacks();
  showToast(`Pack "${pk.name}" supprimé`);
  render();
}
function togglePackActive(id) {
  const pk = S.packs.find(p => p.id === id);
  if (!pk) return;
  pk.active = !pk.active;
  persistPacks();
  showToast(pk.active ? `"${pk.name}" activé` : `"${pk.name}" désactivé`);
  render();
}
function duplicatePack(id) {
  const pk = S.packs.find(p => p.id === id);
  if (!pk) return;
  S.packs.unshift({ ...pk, id: Date.now(), name: pk.name + ' (copie)', createdAt: new Date().toISOString() });
  persistPacks();
  showToast('Pack dupliqué');
  render();
}
function startNewPack() {
  resetPackForm();
  S.view = 'pack-form';
  render();
}

// ── Unit combobox actions (DOM direct — zéro render() pendant la frappe) ──
function _unitDropHTML() {
  const q = (S.form.unit || '').toLowerCase();
  const safe = q.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const filtered = UNITS.filter(u => u.toLowerCase().includes(q));
  if (!filtered.length) return `<div class="unit-opt" style="color:var(--text-3);cursor:default">${t('noResults')}</div>`;
  return filtered.map(u => {
    const hi = q ? u.replace(new RegExp(safe,'gi'), m => `<strong>${m}</strong>`) : u;
    return `<div class="unit-opt" onmousedown="event.preventDefault()" onclick="selectUnit('${u}')">${hi}</div>`;
  }).join('');
}
function openUnitDrop() {
  S.unitDropOpen = true;
  const wrap = document.getElementById('unit-combo-wrap');
  if (!wrap || document.getElementById('unit-dropdown')) return;
  const dd = document.createElement('div');
  dd.className = 'unit-dropdown'; dd.id = 'unit-dropdown';
  dd.innerHTML = _unitDropHTML();
  wrap.appendChild(dd);
}
function updateUnitDrop() {
  const inp = document.getElementById('unit-input');
  if (inp) S.form.unit = inp.value;
  const dd = document.getElementById('unit-dropdown');
  if (!dd) { openUnitDrop(); return; }
  dd.innerHTML = _unitDropHTML();
}
function closeUnitDrop() {
  S.unitDropOpen = false;
  const dd = document.getElementById('unit-dropdown');
  if (dd) dd.remove();
}
function selectUnit(u) {
  S.form.unit = u; S.unitDropOpen = false; S.unitCondVal = ''; S.unitCondOther = '';
  closeUnitDrop();
  render(); // re-render uniquement pour afficher/cacher la section conditionnelle
}
function selectUnitCond(v) { S.unitCondVal = v; S.unitCondOther = ''; render(); }

async function saveAccountInfo() {
  const nameVal  = ($('set-name')?.value  || '').trim();
  const bizVal   = ($('set-biz')?.value   || '').trim();
  if (!nameVal) { showToast(t('nameRequired'), 'error'); return; }
  try {
    await api('PUT', '/api/auth/profile', { name: nameVal, business_name: bizVal });
    S.session.name     = nameVal;
    S.session.business = bizVal;
    saveSession({ ...S.session, token: S.token });
    S.settingsEdit = false;
    showToast(t('infoUpdated'));
    render();
  } catch(e) {
    showToast(e.message, 'error');
  }
}

function toggleDark() {
  S.darkMode = !S.darkMode;
  document.body.classList.toggle('dark', S.darkMode);
  // Support data-theme pour nouveaux styles dark
  if (S.darkMode) {
    document.documentElement.setAttribute('data-theme', 'dark');
    document.body.setAttribute('data-theme', 'dark');
  } else {
    document.documentElement.removeAttribute('data-theme');
    document.body.removeAttribute('data-theme');
  }
  // Persist preference
  localStorage.setItem('stockr_dark_mode', S.darkMode ? '1' : '0');
  showToast(S.darkMode ? '🌙 Mode sombre activé' : '☀️ Mode clair activé', 'success');
  render();
}

function applyTheme() {
  const saved = localStorage.getItem('stockr_dark_mode');
  if (saved === '1') {
    S.darkMode = true;
    document.body.classList.add('dark');
    document.documentElement.setAttribute('data-theme', 'dark');
    document.body.setAttribute('data-theme', 'dark');
  } else if (saved === '0') {
    S.darkMode = false;
  } else {
    // Auto: match system preference
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      S.darkMode = true;
      document.body.classList.add('dark');
      document.documentElement.setAttribute('data-theme', 'dark');
      document.body.setAttribute('data-theme', 'dark');
    }
  }
}

function changeCurrency(code) {
  if (!S.session) return;
  S.session.currency = code;
  S.session.currency_symbol = getCurrencySymbol(code);
  // Save to localStorage
  const saved = JSON.parse(localStorage.getItem('baro_session') || '{}');
  saved.currency = code;
  saved.currency_symbol = S.session.currency_symbol;
  localStorage.setItem('baro_session', JSON.stringify(saved));
  showToast(t('infoUpdated'));
  render();
}

function changeTaxRate(val) {
  if (!S.session) return;
  S.session.tax_rate = parseFloat(val) || 0;
  const saved = JSON.parse(localStorage.getItem('baro_session') || '{}');
  saved.tax_rate = S.session.tax_rate;
  localStorage.setItem('baro_session', JSON.stringify(saved));
  showToast(t('infoUpdated'));
}

// ── Type d'activité : Revendeur / Transformateur / Mixte ─────
function getBusinessType() {
  return S.session?.businessType || localStorage.getItem('stockr_business_type') || 'maker';
}
function changeBusinessType(type) {
  if (!['reseller','maker','mixed'].includes(type)) return;
  if (!S.session) S.session = {};
  S.session.businessType = type;
  localStorage.setItem('stockr_business_type', type);
  const saved = JSON.parse(localStorage.getItem('stockr_session') || '{}');
  saved.businessType = type;
  localStorage.setItem('stockr_session', JSON.stringify(saved));
  const labels = { reseller:'🏪 Revendeur', maker:'🏭 Transformateur', mixed:'🔀 Mixte' };
  showToast(`Mode ${labels[type]} activé`);
  render();
}
// Helpers pour l'UI
function bt_showProducts() { const t = getBusinessType(); return t === 'maker' || t === 'mixed'; }
function bt_showStock()    { const t = getBusinessType(); return t === 'reseller' || t === 'maker' || t === 'mixed'; }

// ── PACKS / BUNDLES ───────────────────────────
function packOriginalPrice(pack) {
  if (!pack?.items?.length) return 0;
  return pack.items.reduce((s, it) => {
    const p = S.products.find(pp => pp.id === it.productId);
    return p ? s + (p.price || 0) * (it.qty || 1) : s;
  }, 0);
}
function packFinalPrice(pack) {
  if (!pack) return 0;
  if (pack.autoPrice) {
    const orig = packOriginalPrice(pack);
    return Math.max(0, Math.round(orig * (100 - (pack.discount||0)) / 100));
  }
  return Math.max(0, pack.price || 0);
}
function packCostPrice(pack) {
  if (!pack?.items?.length) return 0;
  return pack.items.reduce((s, it) => {
    const p = S.products.find(pp => pp.id === it.productId);
    return p ? s + (p.purchasePrice || 0) * (it.qty || 1) : s;
  }, 0);
}
function packMaxAvailable(pack) {
  if (!pack?.items?.length) return 0;
  let min = Infinity;
  for (const it of pack.items) {
    const p = S.products.find(pp => pp.id === it.productId);
    if (!p) return 0;
    const avail = productMaxMake(p);
    const canForThis = Math.floor(avail / (it.qty || 1));
    if (canForThis < min) min = canForThis;
  }
  return min === Infinity ? 0 : min;
}
function packSavings(pack) {
  const orig = packOriginalPrice(pack);
  const fin  = packFinalPrice(pack);
  return Math.max(0, orig - fin);
}
function persistPacks() { localStorage.setItem('stockr_packs', JSON.stringify(S.packs||[])); }
// Pour un revendeur, les ventes se font directement sur les articles
function bt_sellableItems() {
  const t = getBusinessType();
  const bc = S.boutiqueConfig || {};
  const boutiqueArticleIds = new Set(bc.articles || []);
  const boutiqueProductIds = new Set(bc.products || []);
  const boutiquePackIds    = new Set(bc.packs    || []);

  // Packs (uniquement si produits visibles - un pack est fait de produits)
  const packs = (bt_showProducts() && Array.isArray(S.packs)) ? S.packs
    .filter(pk => pk.active !== false && pk.items?.length)
    .map(pk => ({
      id: 'pack_' + pk.id, packId: pk.id, name: '📦 ' + pk.name,
      price: packFinalPrice(pk), purchasePrice: packCostPrice(pk),
      stock: packMaxAvailable(pk), unit: 'pack', kind: 'pack',
      inBoutique: boutiquePackIds.has(pk.id),
    })) : [];

  if (t === 'reseller') {
    // L'article est le produit : doit avoir un prix de vente
    return S.articles.filter(a => (a.price||0) > 0 && (a.stock||0) > 0).map(a => ({
      id: 'art_' + a.id,
      articleId: a.id,
      name: a.name,
      price: a.price,
      purchasePrice: a.purchasePrice || 0,
      stock: a.stock,
      unit: a.unit,
      kind: 'article',
      inBoutique: boutiqueArticleIds.has(a.id),
    }));
  }
  // maker / mixed : produits classiques (+ articles si mixte) + packs
  const prods = S.products.map(p => ({
    id:'prod_'+p.id, productId:p.id, name:p.name, price:p.price,
    purchasePrice:p.purchasePrice||0, stock:productMaxMake(p), unit:'u', kind:'product',
    inBoutique: boutiqueProductIds.has(p.id),
  }));
  if (t === 'mixed') {
    const arts = S.articles.filter(a => (a.price||0) > 0 && (a.stock||0) > 0).map(a => ({
      id:'art_'+a.id, articleId:a.id, name:a.name+' (stock direct)', price:a.price,
      purchasePrice:a.purchasePrice||0, stock:a.stock, unit:a.unit, kind:'article',
      inBoutique: boutiqueArticleIds.has(a.id),
    }));
    return [...packs, ...prods, ...arts];
  }
  return [...packs, ...prods];
}

// ── Bannière reçu post-vente ──────────────────
function showReceiptBanner(sales, total) {
  const existing = document.getElementById('receipt-banner');
  if (existing) existing.remove();
  const sym = S.session?.currency_symbol || 'FCFA';
  const el = document.createElement('div');
  el.id = 'receipt-banner';
  el.className = 'receipt-banner';
  // Stocker les ventes dans un attribut data sérialisé
  const sid = 'rb_' + Date.now();
  window[sid] = sales;
  el.innerHTML = `
    <div class="receipt-banner-left">
      <div class="receipt-banner-title">${t('saleConfirmed')}</div>
      <div class="receipt-banner-total">${fmt(total)} ${sym}</div>
    </div>
    <div class="receipt-banner-btns">
      <button class="rb-btn rb-pdf" onclick="generateInvoicePDF(window['${sid}']);document.getElementById('receipt-banner').remove()">
        ${IC.pdf} PDF
      </button>
      <button class="rb-btn rb-wa" onclick="shareViaWhatsApp(window['${sid}']);document.getElementById('receipt-banner').remove()">
        ${IC.whatsapp} WhatsApp
      </button>
      <button class="rb-close" onclick="document.getElementById('receipt-banner').remove()">✕</button>
    </div>`;
  document.body.appendChild(el);
  setTimeout(() => { const b = document.getElementById('receipt-banner'); if (b) b.remove(); }, 10000);
}

// ── Navigate ──────────────────────────────────
function nav(view, extra={}) {
  try { Object.assign(S, extra); } catch(_){}
  S.view = view;
  try {
    const vEl = document.getElementById('view');
    if (vEl) vEl.scrollTop = 0;
  } catch(_){}
  render();
}
// Expose immédiatement pour que les onclick inline fonctionnent dès le premier clic,
// même avant DOMContentLoaded.
if (typeof window !== 'undefined') window.nav = nav;

// ── Render ────────────────────────────────────
let __lastView = null;
function __markViewTransition(newView) {
  // Only trigger CSS animations when the view actually changes.
  // Prevents "blink" on every state update inside the same view.
  const changed = newView !== __lastView;
  __lastView = newView;
  const body = document.body;
  if (!body) return changed;
  if (changed) {
    body.classList.add('view-entering');
    // Remove after one frame cycle so re-renders within the same view stay static
    clearTimeout(window.__viewEnterTimer);
    window.__viewEnterTimer = setTimeout(() => body.classList.remove('view-entering'), 450);
  } else {
    body.classList.remove('view-entering');
  }
  return changed;
}

// ── Anti-blink : capture/restaure focus, selection, scroll avant innerHTML ─
function __snapshotUIState() {
  const ae = document.activeElement;
  let focus = null;
  if (ae && ae.id && (ae.tagName === 'INPUT' || ae.tagName === 'TEXTAREA' || ae.tagName === 'SELECT')) {
    focus = {
      id: ae.id,
      selectionStart: typeof ae.selectionStart === 'number' ? ae.selectionStart : null,
      selectionEnd: typeof ae.selectionEnd === 'number' ? ae.selectionEnd : null,
      scrollTop: ae.scrollTop,
    };
  }
  const vEl = document.getElementById('view');
  const scrollY = window.scrollY || 0;
  const vScroll = vEl ? vEl.scrollTop : 0;
  return { focus, scrollY, vScroll };
}
function __restoreUIState(snap) {
  if (!snap) return;
  requestAnimationFrame(() => {
    if (snap.focus) {
      const el = document.getElementById(snap.focus.id);
      if (el) {
        try { el.focus({ preventScroll: true }); } catch(e) { try { el.focus(); } catch(_){} }
        if (snap.focus.selectionStart !== null && typeof el.setSelectionRange === 'function') {
          try { el.setSelectionRange(snap.focus.selectionStart, snap.focus.selectionEnd); } catch(e){}
        }
      }
    }
    // Ne PAS restaurer scroll si on change de view
  });
}

// ── render() avec débounce RAF + préservation focus ──
let __renderPending = false;
let __renderRAF = null;
function render() {
  // Batch multiples renders dans la même frame
  if (__renderPending) return;
  __renderPending = true;
  if (__renderRAF) cancelAnimationFrame(__renderRAF);
  __renderRAF = requestAnimationFrame(() => {
    __renderPending = false;
    __renderRAF = null;
    _doRender();
  });
}

function _doRender() {
  const viewEl = $('view');
  const navEl  = $('nav');
  const snap = __snapshotUIState();
  const sameView = __lastView === (S.view || 'home') || (!S.session && __lastView === '__auth');

  // 2FA en attente → écran vérification
  if (S.twoFAPending && S.view === '2fa-verify') {
    navEl.style.display = 'none';
    __markViewTransition('2fa-verify');
    viewEl.innerHTML = v2FAVerify();
    if (!sameView) viewEl.scrollTop = 0;
    __restoreUIState(snap);
    return;
  }

  // Pas de session → écran auth
  if (!S.session) {
    navEl.style.display = 'none';
    __markViewTransition('__auth');
    viewEl.innerHTML = vAuth();
    if (!sameView) viewEl.scrollTop = 0;
    __restoreUIState(snap);
    return;
  }

  // Redirect si onglet masqué par businessType
  if (S.view === 'products' && !bt_showProducts()) S.view = 'home';
  if (S.view === 'pantry'   && !bt_showStock())    S.view = 'home';

  const map = {
    home: vHome, pantry: vPantry, products: vProducts,
    sales: vSales, financial: vFinancial,
    detail: vDetail, add: vAdd, 'add-product': vAddProduct,
    'edit-product': vEditProduct, settings: vSettings,
    spectra: vSpectraEnhanced, clients: vClients, 'add-client': vAddClient,
    'client-detail': vClientDetail, notifications: vNotifications,
    catalog: vCatalog, suppliers: vSuppliers,
    'add-supplier': vAddSupplier, 'supplier-detail': vSupplierDetail,
    'stock-history': vStockHistory, 'purchase-orders': vPurchaseOrdersEnhanced,
    'add-order': vAddOrder, pricing: vPricing, subscription: vSubscription,
    // ── Nouvelles vues v2 ──
    more: vMore, boutique: vBoutique, marketing: vMarketing,
    'social-media': vSocialMedia, 'social-setup': vSocialSetup, 'payments-setup': vPayments,
    integrations: vIntegrations,
    'delivery-setup': vDeliverySetup,
    'whatsapp-setup': vWhatsAppSetup,
    'sms-setup': vSmsSetup,
    'ecommerce-setup': vEcommerceSetup,
    'sheets-setup': vSheetsSetup,
    'pos-setup': vPosSetup,
    'compta-setup': vComptaSetup,
    'promo-form': vPromoForm, 'promo-detail': vPromoDetail,
    'banner-form': vBannerForm, 'popup-form': vPopupForm,
    'review-form': vReviewForm, 'tracking-form': vTrackingForm,
    'boutique-appearance': vBoutiqueAppearance,
    'boutique-domain': vBoutiqueDomain,
    'boutique-pixels': vBoutiquePixels,
    'boutique-code': vBoutiqueCode,
    'boutique-seo': vBoutiqueSEO,
    'boutique-hours': vBoutiqueHours,
    'boutique-policies': vBoutiquePolicies,
    'boutique-faq': vBoutiqueFAQ,
    'api-settings': vApiSettings,
    'loyalty': () => { S.marketingTab = 'loyalty'; S.view = 'marketing'; return vMarketing(); },
    'boutique-orders': () => { S.view = 'boutique'; return vBoutique(); },
    'pack-form': vPackForm,
    'exports': vExports,
    // ── BATCH 5 : Équipe, Audit, Apparence, Sécurité, 2FA ──
    'team':             vTeam,
    'add-team-member':  vAddTeamMember,
    'audit-log':        vAuditLog,
    'appearance':       vAppearance,
    'security':         vSecurity,
    'spectra-ai-setup': vSpectraAISetup,
    'oauth-setup': vOAuthSetup,
    'notifications-setup': vNotificationsSetup,
    'video-library': vVideoLibrary,
  };
  const viewChanged = __markViewTransition(S.view);
  const prevScroll = viewEl.scrollTop;
  viewEl.innerHTML = (map[S.view] || vHome)();
  // Conserve le scroll si on re-render la MÊME view (évite le "blink" de remontée)
  if (viewChanged) {
    if (!S.globalSearch) viewEl.scrollTop = 0;
  } else {
    viewEl.scrollTop = prevScroll;
  }

  if (S.view === 'financial') requestAnimationFrame(() => { renderRevenueChart(); renderProfitChart(); });

  // Restore focus (capture précédente)
  __restoreUIState(snap);
  // Backup : focus spécifique global search
  if (S.view === 'home' && S.globalSearch && !snap.focus) {
    const gs = $('global-search');
    if (gs) { gs.focus({ preventScroll: true }); gs.setSelectionRange(gs.value.length, gs.value.length); }
  }

  const hideNav = ['detail','add','add-product','edit-product','pack-form','add-client','client-detail','notifications','catalog','add-supplier','supplier-detail','stock-history','purchase-orders','add-order','pricing','subscription','boutique','boutique-appearance','boutique-domain','boutique-pixels','boutique-code','boutique-seo','boutique-hours','boutique-policies','boutique-faq','marketing','social-media','social-setup','payments-setup','integrations','delivery-setup','whatsapp-setup','sms-setup','ecommerce-setup','sheets-setup','pos-setup','compta-setup','api-settings','spectra','clients','exports','team','add-team-member','audit-log','appearance','security','2fa-verify'].includes(S.view);
  navEl.style.display = hideNav ? 'none' : '';
  if (!hideNav) navEl.innerHTML = renderNav();
}

function renderNav() {
  const bt = getBusinessType();
  const stockLbl = bt === 'reseller' ? 'Boutique' : bt === 'maker' ? 'Matières' : t('stock');
  const tabs = [
    { id:'home',      icon:IC.home,    label:t('home')     },
    bt_showStock() ? { id:'pantry', icon:IC.box, label:stockLbl } : null,
    bt_showProducts() ? { id:'products', icon:IC.tag, label:t('products') } : null,
    { id:'sales',     icon:IC.dollar,  label:t('sales')    },
    { id:'financial', icon:IC.bar,     label:t('bilan')    },
    { id:'more',      icon:IC.grid,    label:t('more')||'Plus' },
  ].filter(Boolean);
  return tabs.map(tb => `
    <button class="nav-tab ${S.view===tb.id?'active':''}" onclick="nav('${tb.id}')">
      ${tb.icon}
      <span class="nav-label">${tb.label}</span>
    </button>`).join('');
}

// ── AUTH ──────────────────────────────────────
function vAuth() {
  const isLogin = S.authView === 'login';
  if (!isLogin && S.authStep === 2) return vAuthStep2();

  return `
  <div class="auth-wrap">
    <div class="auth-card">
      <div class="auth-logo">${IC.baro || IC.box}<span>BARO</span></div>
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:16px">
        <button onclick="setLang('fr')" style="padding:4px 10px;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;border:1px solid ${_lang==='fr'?'var(--accent)':'var(--border)'};background:${_lang==='fr'?'var(--accent-light)':'transparent'};color:${_lang==='fr'?'var(--accent)':'var(--text-3)'}">FR</button>
        <button onclick="setLang('en')" style="padding:4px 10px;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer;border:1px solid ${_lang==='en'?'var(--accent)':'var(--border)'};background:${_lang==='en'?'var(--accent-light)':'transparent'};color:${_lang==='en'?'var(--accent)':'var(--text-3)'}">EN</button>
      </div>
      <div class="auth-title">${isLogin ? t('login') : t('register')}</div>
      <div class="auth-sub">${isLogin ? t('loginSub') : 'Étape 1/2'}</div>

      ${!isLogin ? `
      <div class="form-group">
        <label class="form-label">Prénom / Nom *</label>
        <input class="input" id="auth-name" type="text" placeholder="ex: Fatou Diallo" autocomplete="name" value="${S.authName}" oninput="S.authName=this.value">
      </div>
      <div class="form-group">
        <label class="form-label">Nom du commerce</label>
        <input class="input" id="auth-biz" type="text" placeholder="ex: Boutique Wax de Fatou" value="${S.authBiz||''}" oninput="S.authBiz=this.value">
      </div>` : ''}

      <div class="form-group">
        <label class="form-label">Email *</label>
        <input class="input" id="auth-email" type="email" placeholder="ton@email.com" autocomplete="email" value="${S.authEmail}" oninput="S.authEmail=this.value">
      </div>
      <div class="form-group">
        <label class="form-label">Mot de passe *</label>
        <div class="pwd-wrap">
          <input class="input ${S.authShowPwd?'':'pwd-masked'}" id="auth-pwd" type="text" placeholder="••••••••" autocomplete="${isLogin?'current-password':'new-password'}" value="${S.authPwd}" oninput="S.authPwd=this.value">
          <button class="pwd-eye" onclick="toggleAuthPwd(event)" type="button">${S.authShowPwd?IC.eyeOff:IC.eye}</button>
        </div>
      </div>
      ${!isLogin ? `
      <div class="form-group">
        <label class="form-label">Confirmer le mot de passe *</label>
        <div class="pwd-wrap">
          <input class="input ${S.authShowPwd?'':'pwd-masked'}" id="auth-pwd2" type="text" placeholder="••••••••" autocomplete="new-password" value="${S.authPwd2}" oninput="S.authPwd2=this.value">
        </div>
      </div>` : ''}

      <button class="btn btn-primary" style="margin-top:8px" onclick="${isLogin ? 'doLogin()' : 'authNextStep()'}">
        ${isLogin ? t('loginBtn') : t('next') + ' →'}
      </button>

      ${isLogin && window.PublicKeyCredential ? `
      <!-- Separator -->
      <div style="display:flex;align-items:center;gap:10px;margin:18px 0 12px">
        <div style="flex:1;height:1px;background:var(--border)"></div>
        <div style="font-size:11px;color:var(--text-3);font-weight:600">OU</div>
        <div style="flex:1;height:1px;background:var(--border)"></div>
      </div>

      <!-- Connexion biométrique (WebAuthn natif navigateur — 100% fonctionnel) -->
      <button class="btn" onclick="loginBiometric()" style="background:var(--card-bg);color:var(--accent);border:2px solid var(--accent);display:flex;align-items:center;justify-content:center;gap:10px;font-weight:700;padding:12px;width:100%">
        <span style="font-size:18px">👆</span>
        Connexion biométrique
      </button>
      ` : ''}
      ${isLogin ? `
      <div style="margin-top:12px;text-align:center;display:flex;align-items:center;justify-content:center;gap:6px;font-size:10px;color:var(--text-3)">
        <span>🔒</span><span>Connexion sécurisée SSL</span>
      </div>
      ` : ''}

      <div class="auth-switch">
        ${isLogin ? t('noAccount') : t('hasAccount')}
        <button onclick="S.authView='${isLogin?'register':'login'}';S.authStep=1;S.authShowPwd=false;render()">
          ${isLogin ? t('register') : t('loginBtn')}
        </button>
      </div>
    </div>
  </div>`;
}

// ── Social / biometric login : flux fonctionnels ────────────────
// Google Identity Services et Apple Sign-In doivent être chargés via index.html en prod.
// En absence : modal interne propre (pas de prompt() natif) qui crée une vraie session.
function __socialLoginCreate(provider, email, name, avatar) {
  const token = 'social_' + provider + '_' + Math.random().toString(36).slice(2, 12);
  const session = {
    token,
    id: 'u_' + provider + '_' + Date.now(),
    email: email,
    name: name,
    business: (name || 'Ma Boutique'),
    provider,
    avatar: avatar || (provider === 'google' ? '🟢' : provider === 'apple' ? '🍎' : '👤'),
    profile:         S.authProfile || 'reseller',
    businessType:    S.authProfile === 'transformer' ? 'maker' : S.authProfile === 'reseller' ? 'reseller' : 'mixed',
    country:         S.authCountry || 'CI',
    currency:        S.authCurrency || 'XOF',
    currency_symbol: getCurrencySymbol(S.authCurrency || 'XOF'),
    language:        S.authLang || 'fr',
    tax_rate:        0,
    createdAt: Date.now(),
  };
  try {
    localStorage.setItem('stockr_session', JSON.stringify(session));
    localStorage.setItem('stockr_token', token);
    localStorage.setItem('stockr_business_type', session.businessType);
  } catch(e){}
  S.token = token;
  S.session = session;
  // Session vierge (pas de seed auto pour éviter faux produits)
  S.articles = []; S.products = []; S.clients = []; S.sales = [];
  if (typeof logAudit === 'function') logAudit('auth', 'login_success', { provider, email });
  S.view = 'home';
  render();
  try { loadData(); } catch(e){}
  showToast('✅ Connecté avec ' + provider.charAt(0).toUpperCase() + provider.slice(1) + ' — ' + name, 'success');
  // Proposer biométrie après login social
  setTimeout(() => {
    if (window.PublicKeyCredential && !localStorage.getItem('stockr_webauthn_cred')) {
      if (confirm('🔐 Activer la biométrie pour sécuriser ce compte ?\n(Empreinte / FaceID / PIN)')) {
        loginBiometric();
      }
    }
  }, 1500);
}

