// ── STOCK MOVEMENT HISTORY ──────────────────
function logMovement(articleName, type, qty, note) {
  const mv = {
    id: Date.now(),
    article: articleName,
    type, // 'entry' | 'exit' | 'adjustment'
    qty,
    note: note || '',
    date: new Date().toISOString(),
  };
  S.stockMovements.unshift(mv);
  if (S.stockMovements.length > 500) S.stockMovements = S.stockMovements.slice(0, 500);
  localStorage.setItem('baro_movements', JSON.stringify(S.stockMovements));
}

// ── STOCK TRANSFER BETWEEN LOCATIONS ────────
function openStockTransfer() {
  if (S.locations.length < 2) { showToast('Ajoutez au moins 2 emplacements', 'error'); return; }
  if (S.articles.length === 0) { showToast('Aucun article à transférer', 'error'); return; }
  // Simple prompts-based flow (keeps UI lean; full form could come later)
  const articleNames = S.articles.map((a,i) => `${i+1}. ${a.name} (${fmtQty(a.stock)} ${a.unit})`).join('\n');
  const idxRaw = prompt('Article à transférer (entrer le numéro) :\n\n' + articleNames);
  if (!idxRaw) return;
  const idx = Number(idxRaw) - 1;
  if (!(idx >= 0 && idx < S.articles.length)) { showToast('Numéro invalide', 'error'); return; }
  const article = S.articles[idx];
  if (article.stock <= 0) { showToast('Stock insuffisant', 'error'); return; }
  const locList = S.locations.map((l,i) => `${i+1}. ${l.name}${article.locationId===l.id?' (actuel)':''}`).join('\n');
  const fromRaw = prompt(`Transférer depuis ?\n\n${locList}`, String((S.locations.findIndex(l=>l.id===article.locationId)+1)||1));
  if (!fromRaw) return;
  const fromIdx = Number(fromRaw) - 1;
  if (!(fromIdx >= 0 && fromIdx < S.locations.length)) { showToast('Origine invalide', 'error'); return; }
  const toRaw = prompt(`Transférer vers ?\n\n${locList}`);
  if (!toRaw) return;
  const toIdx = Number(toRaw) - 1;
  if (!(toIdx >= 0 && toIdx < S.locations.length) || toIdx === fromIdx) { showToast('Destination invalide', 'error'); return; }
  const qtyRaw = prompt(`Quantité à transférer (max ${fmtQty(article.stock)} ${article.unit}) :`, String(article.stock));
  if (!qtyRaw) return;
  const qty = Number(qtyRaw);
  if (!isFinite(qty) || qty <= 0 || qty > article.stock) { showToast('Quantité invalide', 'error'); return; }
  // Execute : decrement source article, find or create mirror article at destination
  const fromLoc = S.locations[fromIdx];
  const toLoc = S.locations[toIdx];
  // Check if a mirror article exists at destination
  let destArticle = S.articles.find(a => a.name === article.name && a.unit === article.unit && a.locationId === toLoc.id);
  if (!destArticle) {
    // Create a mirror copy
    destArticle = { ...article, id: Date.now() + Math.random(), stock: 0, locationId: toLoc.id };
    S.articles.push(destArticle);
  }
  article.stock -= qty;
  destArticle.stock += qty;
  localStorage.setItem('stockr_articles', JSON.stringify(S.articles));
  logMovement(article.name, 'exit', qty, `Transfert → ${toLoc.name}`);
  logMovement(destArticle.name, 'entry', qty, `Transfert ← ${fromLoc.name}`);
  logActivity('stock', `Transfert : ${qty} ${article.unit} ${article.name} (${fromLoc.name} → ${toLoc.name})`);
  showToast(`${qty} ${article.unit} transférés`, 'success');
  render();
}

function vStockHistory() {
  const movements = S.stockMovements.slice(0, 100);
  return `
  <div class="sub-hero">
    <button class="back-btn-dark" style="margin-bottom:14px" onclick="nav('more')">${IC.left}</button>
    <div class="sub-hero-title">${t('stockHistory')}</div>
    <div class="sub-hero-sub">${S.stockMovements.length} ${t('articles').toLowerCase()}</div>
  </div>
  <div class="container">
    ${movements.length === 0 ? `
    <div class="empty-state">
      ${IC.inbox}
      <div class="empty-title">${t('noMovements')}</div>
    </div>` : movements.map((m, i) => {
      const typeColor = m.type === 'entry' ? 'var(--success)' : m.type === 'exit' ? 'var(--danger)' : 'var(--warning)';
      const typeLabel = m.type === 'entry' ? t('entry') : m.type === 'exit' ? t('exit') : t('adjustment');
      const sign = m.type === 'entry' ? '+' : m.type === 'exit' ? '-' : '';
      return `
    <div class="card anim" style="margin-bottom:4px;border-left:3px solid ${typeColor};animation-delay:${i*0.02}s">
      <div style="display:flex;justify-content:space-between;align-items:center">
        <div>
          <div style="font-weight:700;font-size:13px">${m.article}</div>
          <div style="font-size:11px;color:var(--text-3)">${typeLabel} · ${fmtDate(m.date)}${m.note ? ' · '+m.note : ''}</div>
        </div>
        <div style="font-weight:800;color:${typeColor};font-size:15px">${sign}${m.qty}</div>
      </div>
    </div>`;
    }).join('')}
  </div>`;
}

// ── SPECTRA DEMO MODE ───────────────────────
function spectraRunDemo() {
  S.spectra.step = 'loading';
  S.spectra.demoMode = 'audit';
  render();
  // Simulate realistic detection after 2.5s using existing articles
  setTimeout(() => {
    const fallbackDB = [
      { detected_name: 'Riz 5kg', matched_name: 'Riz 5kg', quantity: 8, confidence: 94, matched_unit: 'sac' },
      { detected_name: 'Huile végétale 1L', matched_name: 'Huile végétale 1L', quantity: 12, confidence: 91, matched_unit: 'l' },
      { detected_name: 'Sucre 1kg', matched_name: 'Sucre 1kg', quantity: 3, confidence: 97, matched_unit: 'kg' },
      { detected_name: 'Savon Marseille', matched_name: 'Savon Marseille', quantity: 20, confidence: 89, matched_unit: 'pce' },
      { detected_name: 'Farine 1kg', matched_name: 'Farine 1kg', quantity: 5, confidence: 93, matched_unit: 'kg' },
    ];
    let demoItems;
    if (S.articles.length >= 3) {
      // Use real articles with realistic gap simulation
      demoItems = S.articles.slice(0, Math.min(6, S.articles.length)).map(a => {
        const stk = a.qty !== undefined ? a.qty : a.stock;
        // Create gaps: some items match, some are missing, some extra
        const variance = Math.random();
        let qty;
        if (variance < 0.3) qty = Math.max(0, stk - Math.ceil(Math.random() * 3)); // missing
        else if (variance < 0.5) qty = stk + Math.ceil(Math.random() * 2); // extra
        else qty = stk; // match
        return {
          detected_name: a.name,
          matched_name: a.name,
          matched_id: a.id,
          matched_unit: a.unit || 'pce',
          quantity: Math.max(0, qty),
          confidence: Math.floor(86 + Math.random() * 13),
        };
      });
    } else {
      demoItems = fallbackDB;
    }
    S.spectra.compareResults = demoItems;
    S.spectra.step = 'compare';
    logActivity('spectra', _lang === 'fr' ? 'Audit Spectra effectué (démo)' : 'Spectra audit completed (demo)');
    render();
  }, 2500);
}

function spectraRunDemoReception() {
  S.spectra.step = 'loading';
  S.spectra.demoMode = 'reception';
  render();
  setTimeout(() => {
    let receptionItems;
    if (S.articles.length >= 2) {
      receptionItems = S.articles.slice(0, Math.min(4, S.articles.length)).map(a => ({
        detected_name: a.name,
        matched_name: a.name,
        matched_id: a.id,
        matched_unit: a.unit || 'pce',
        quantity: Math.ceil(Math.random() * 10 + 2),
        confidence: Math.floor(88 + Math.random() * 11),
      }));
    } else {
      receptionItems = [
        { detected_name: 'Bouteilles eau 1.5L', matched_name: 'Bouteilles eau 1.5L', quantity: 24, confidence: 96, matched_unit: 'pce' },
        { detected_name: 'Gobelets plastique', matched_name: 'Gobelets plastique', quantity: 10, confidence: 91, matched_unit: 'pce' },
        { detected_name: 'Serviettes', matched_name: 'Serviettes', quantity: 6, confidence: 87, matched_unit: 'lot' },
      ];
    }
    S.spectra.receptionItems = receptionItems;
    S.spectra.step = 'reception';
    render();
  }, 2500);
}

// ── DAILY GOAL ──────────────────────────────
function editDailyGoal() {
  const current = Number(localStorage.getItem('stockr_daily_goal')) || 0;
  const currentType = localStorage.getItem('stockr_goal_type') || 'revenue'; // revenue | sales | profit
  const currentPeriod = localStorage.getItem('stockr_goal_period') || 'day'; // day | week | month | year
  const thirtyDaysAgo = new Date(); thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
  const last30 = S.sales.filter(s => new Date(s.date) >= thirtyDaysAgo);
  const avg30CA = last30.length > 0 ? Math.round(last30.reduce((x,s)=>x+s.total,0) / 30) : 0;
  const avg30Profit = last30.length > 0 ? Math.round(last30.reduce((x,s)=>x+(s.profit||0),0) / 30) : 0;
  const avg30Sales = Math.round(last30.length / 30);
  const sugCA = Math.max(1000, Math.round((avg30CA * 1.2) / 500) * 500);
  const sugProfit = Math.max(500, Math.round((avg30Profit * 1.2) / 100) * 100);
  const sugSales = Math.max(1, Math.round(avg30Sales * 1.2));

  // Build modal overlay
  const existing = document.getElementById('goal-modal');
  if (existing) existing.remove();
  const modal = document.createElement('div');
  modal.id = 'goal-modal';
  modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:10000;display:flex;align-items:center;justify-content:center;padding:20px;backdrop-filter:blur(4px);animation:fadeIn .2s ease';
  modal.onclick = (e) => { if (e.target === modal) modal.remove(); };

  // Helper global : appelé directement par les boutons (pas d'event custom)
  window.__goalSetType = (t) => {
    const m = document.getElementById('goal-modal');
    if (!m) return;
    const input = document.getElementById('goal-value-input');
    if (input) m.dataset.value = input.value;
    m.dataset.type = t;
    m.innerHTML = render_body();
  };
  window.__goalSetPeriod = (p) => {
    const m = document.getElementById('goal-modal');
    if (!m) return;
    const input = document.getElementById('goal-value-input');
    if (input) m.dataset.value = input.value;
    m.dataset.period = p;
    m.innerHTML = render_body();
  };
  window.__goalSetValue = (v) => {
    const m = document.getElementById('goal-modal');
    if (!m) return;
    m.dataset.value = String(v);
    const input = document.getElementById('goal-value-input');
    if (input) input.value = String(v);
  };

  const render_body = () => {
    const type = modal.dataset.type || currentType;
    const period = modal.dataset.period || currentPeriod;
    const valueInput = modal.dataset.value;
    const unit = type === 'sales' ? 'ventes' : sym();
    const periodLabel = period === 'day' ? 'jour' : period === 'week' ? 'semaine' : period === 'month' ? 'mois' : 'année';
    const periodMult = period === 'day' ? 1 : period === 'week' ? 7 : period === 'month' ? 30 : 365;
    const sug = type === 'revenue' ? sugCA * periodMult : type === 'profit' ? sugProfit * periodMult : sugSales * periodMult;
    const avg = type === 'revenue' ? avg30CA * periodMult : type === 'profit' ? avg30Profit * periodMult : avg30Sales * periodMult;
    return `
    <div style="background:var(--surface);border-radius:16px;max-width:420px;width:100%;max-height:90vh;overflow-y:auto;box-shadow:0 20px 60px rgba(0,0,0,.3);animation:slideUp .25s ease" onclick="event.stopPropagation()">
      <div style="padding:18px 20px;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between">
        <div>
          <div style="font-size:18px;font-weight:800;color:var(--text-1)">🎯 Configurer l'objectif</div>
          <div style="font-size:11px;color:var(--text-3);margin-top:2px">Suivez vos performances en temps réel</div>
        </div>
        <button type="button" style="width:32px;height:32px;border-radius:50%;border:none;background:var(--gray-1);color:var(--text-2);font-size:18px;cursor:pointer" onclick="document.getElementById('goal-modal').remove()">×</button>
      </div>
      <div style="padding:16px 20px">
        <div style="margin-bottom:14px">
          <label style="font-size:11px;color:var(--text-3);font-weight:700;letter-spacing:.3px;text-transform:uppercase;margin-bottom:6px;display:block">Type d'objectif</label>
          <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:6px">
            <button type="button" class="goal-type-btn ${type==='revenue'?'active':''}" style="padding:10px 6px;border-radius:8px;border:1.5px solid ${type==='revenue'?'var(--accent)':'var(--border)'};background:${type==='revenue'?'rgba(79,70,229,0.08)':'var(--surface)'};cursor:pointer;text-align:center" onclick="__goalSetType('revenue')">
              <div style="font-size:20px;margin-bottom:2px">💰</div>
              <div style="font-size:11px;font-weight:700;color:${type==='revenue'?'var(--accent)':'var(--text-2)'}">CA</div>
            </button>
            <button type="button" class="goal-type-btn ${type==='profit'?'active':''}" style="padding:10px 6px;border-radius:8px;border:1.5px solid ${type==='profit'?'var(--success)':'var(--border)'};background:${type==='profit'?'rgba(16,185,129,0.08)':'var(--surface)'};cursor:pointer;text-align:center" onclick="__goalSetType('profit')">
              <div style="font-size:20px;margin-bottom:2px">📈</div>
              <div style="font-size:11px;font-weight:700;color:${type==='profit'?'var(--success)':'var(--text-2)'}">Bénéfice</div>
            </button>
            <button type="button" class="goal-type-btn ${type==='sales'?'active':''}" style="padding:10px 6px;border-radius:8px;border:1.5px solid ${type==='sales'?'#EC4899':'var(--border)'};background:${type==='sales'?'rgba(236,72,153,0.08)':'var(--surface)'};cursor:pointer;text-align:center" onclick="__goalSetType('sales')">
              <div style="font-size:20px;margin-bottom:2px">🛒</div>
              <div style="font-size:11px;font-weight:700;color:${type==='sales'?'#EC4899':'var(--text-2)'}">Nb ventes</div>
            </button>
          </div>
        </div>

        <div style="margin-bottom:14px">
          <label style="font-size:11px;color:var(--text-3);font-weight:700;letter-spacing:.3px;text-transform:uppercase;margin-bottom:6px;display:block">Période</label>
          <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:6px">
            ${['day','week','month','year'].map(p => `
              <button type="button" style="padding:8px 4px;border-radius:8px;border:1.5px solid ${period===p?'var(--accent)':'var(--border)'};background:${period===p?'rgba(79,70,229,0.08)':'var(--surface)'};cursor:pointer;font-size:11px;font-weight:600;color:${period===p?'var(--accent)':'var(--text-2)'}" onclick="__goalSetPeriod('${p}')">
                ${p==='day'?'📅 Jour':p==='week'?'📆 Sem.':p==='month'?'🗓️ Mois':'🎊 Année'}
              </button>
            `).join('')}
          </div>
        </div>

        <div style="background:var(--gray-1);border-radius:10px;padding:12px;margin-bottom:14px;border:1px solid var(--border)">
          <div style="font-size:11px;color:var(--text-3);font-weight:600;margin-bottom:4px">📊 Vos stats réelles (30j)</div>
          <div style="font-size:13px;color:var(--text-2)">Moyenne / ${periodLabel} : <b style="color:var(--text-1)">${fmt(avg)} ${unit}</b></div>
          <div style="font-size:11px;color:var(--text-3);margin-top:2px">💡 Suggestion : <b style="color:var(--accent)">${fmt(sug)} ${unit}</b> (<em>+20% vs moyenne</em>)</div>
        </div>

        <div style="margin-bottom:14px">
          <label style="font-size:11px;color:var(--text-3);font-weight:700;letter-spacing:.3px;text-transform:uppercase;margin-bottom:6px;display:block">Mon objectif / ${periodLabel} (${unit})</label>
          <input id="goal-value-input" class="input" type="number" min="0" step="${type==='sales'?1:500}" value="${valueInput !== undefined ? valueInput : (current > 0 ? current : sug)}" style="font-size:18px;font-weight:700;text-align:center;min-height:50px" oninput="document.getElementById('goal-modal').dataset.value=this.value">
          <div style="display:flex;gap:6px;margin-top:8px;flex-wrap:wrap">
            <button type="button" class="chip" onclick="__goalSetValue(${sug})">💡 Suggéré</button>
            <button type="button" class="chip" onclick="__goalSetValue(${Math.round(sug*1.5)})">🚀 Ambitieux (+50%)</button>
            <button type="button" class="chip" onclick="__goalSetValue(${Math.round(sug*2)})">💪 Agressif (×2)</button>
          </div>
        </div>

        <div style="display:flex;gap:8px;margin-top:18px">
          <button type="button" class="btn btn-ghost" style="flex:1" onclick="saveGoalConfig('', '', '')">🗑️ Désactiver</button>
          <button type="button" class="btn btn-primary" style="flex:2" onclick="saveGoalConfig(document.getElementById('goal-value-input').value, document.getElementById('goal-modal').dataset.type||'${type}', document.getElementById('goal-modal').dataset.period||'${period}')">✓ Enregistrer</button>
        </div>
      </div>
    </div>`;
  };

  modal.dataset.type = currentType;
  modal.dataset.period = currentPeriod;
  modal.innerHTML = render_body();
  document.body.appendChild(modal);
}

function saveGoalConfig(value, type, period) {
  const v = String(value).trim();
  if (v === '' || v === '0') {
    localStorage.removeItem('stockr_daily_goal');
    localStorage.removeItem('stockr_goal_type');
    localStorage.removeItem('stockr_goal_period');
    showToast('Objectif désactivé', 'success');
  } else {
    const num = Number(v.replace(/[\s,]/g, ''));
    if (!isFinite(num) || num < 0) { showToast('Valeur invalide', 'error'); return; }
    localStorage.setItem('stockr_daily_goal', String(num));
    if (type) localStorage.setItem('stockr_goal_type', type);
    if (period) localStorage.setItem('stockr_goal_period', period);
    const unit = type === 'sales' ? 'ventes' : sym();
    const periodLabel = period === 'day' ? 'jour' : period === 'week' ? 'semaine' : 'mois';
    showToast(`🎯 Objectif : ${fmt(num)} ${unit} / ${periodLabel}`, 'success');
  }
  const modal = document.getElementById('goal-modal');
  if (modal) modal.remove();
  render();
}

// ── QUICK SALE ──────────────────────────────
function quickSaleProduct(productId) {
  const prod = S.products.find(p => p.id === productId);
  if (!prod) return;
  const sym = S.session?.currency_symbol || 'FCFA';

  // Check stock availability using composition (correct property)
  const comps = prod.composition || [];
  const canMake = comps.length > 0 ? Math.min(...comps.map(comp => {
    const art = S.articles.find(a => a.id === comp.id);
    return art ? Math.floor((art.stock !== undefined ? art.stock : 0) / (comp.qty || 1)) : 0;
  })) : 999;

  if (canMake < 1) {
    showToast(t('insufficientStock'), 'error');
    return;
  }

  // Apply active promo (auto-applicable, sans code)
  let finalPrice = prod.price;
  let promoName = null, promoDiscount = 0, promoCode = null, promoId = null;
  const promo = _getActivePromo(prod.id);
  if (promo) {
    promoId = promo.id;
    promoName = promo.name;
    promoCode = promo.code;
    finalPrice = _applyPromoValue(prod.price, promo);
    promoDiscount = prod.price > 0 ? Math.round((1 - finalPrice/prod.price)*100) : 0;
    _recordPromoUsage(promo.id, null);
  }

  // Create sale
  const sale = {
    id: Date.now(),
    productId: prod.id,
    productName: prod.name,
    qty: 1,
    total: finalPrice,
    profit: finalPrice - (prod.purchasePrice || 0),
    date: new Date().toISOString(),
    method: 'cash',
    paymentMethod: 'cash',
    promoName, promoDiscount, promoCode, promoId,
  };

  // Deduct stock using composition
  if (comps.length > 0) {
    comps.forEach(comp => {
      const art = S.articles.find(a => a.id === comp.id);
      if (art) {
        art.stock = Math.round((art.stock - (comp.qty || 1)) * 10) / 10;
        logMovement(art.name, 'exit', comp.qty || 1, t('quickSale') + ': ' + prod.name);
      }
    });
    localStorage.setItem('baro_articles', JSON.stringify(S.articles));
  }

  // Loyalty points
  if (S.loyaltyConfig?.enabled) {
    sale.loyaltyPoints = Math.floor(finalPrice * (S.loyaltyConfig.pointsPerFcfa || 1));
  }

  S.sales.unshift(sale);
  localStorage.setItem('baro_sales', JSON.stringify(S.sales));
  logActivity('sale', `${prod.name} x1 — ${fmt(prod.price)} ${sym}`);
  showToast(`${t('saleConfirmed')}: ${prod.name} — ${fmt(prod.price)} ${sym}`, 'success');
  render();
}

// ── IMPROVED CSV EXPORT ─────────────────────
function exportFullCSV(type) {
  let csv = '', filename = 'baro-export.csv';
  const sep = ',';
  const sym = S.session?.currency_symbol || 'FCFA';

  if (type === 'articles') {
    filename = 'baro-articles.csv';
    csv = 'Nom,Stock,Unité,Seuil alerte,Prix,' + sym + ',Coût,' + sym + '\n';
    S.articles.forEach(a => {
      const stk = a.qty !== undefined ? a.qty : a.stock;
      csv += `"${a.name}",${stk},"${a.unit||''}",${a.minQty||a.min||0},${a.price||0},${a.cost||0}\n`;
    });
  } else if (type === 'sales') {
    filename = 'baro-ventes.csv';
    csv = 'Date,Produit,Quantité,Total ' + sym + ',Bénéfice ' + sym + ',Client,Paiement\n';
    S.sales.forEach(s => {
      csv += `"${new Date(s.date).toLocaleString()}","${s.productName}",${s.qty},${s.total},${s.profit||0},"${s.clientName||''}","${s.method||''}"\n`;
    });
  } else if (type === 'clients') {
    filename = 'baro-clients.csv';
    csv = 'Nom,Téléphone,Email,Notes,Nb achats,Total dépensé ' + sym + '\n';
    S.clients.forEach(c => {
      const sales = S.sales.filter(s => s.clientId && String(s.clientId) === String(c.id));
      const spent = sales.reduce((s,v) => s + v.total, 0);
      csv += `"${c.name}","${c.phone||''}","${c.email||''}","${(c.notes||'').replace(/"/g,'""')}",${sales.length},${spent}\n`;
    });
  } else if (type === 'suppliers') {
    filename = 'baro-fournisseurs.csv';
    csv = 'Nom,Téléphone,Email,Notes\n';
    S.suppliers.forEach(s => {
      csv += `"${s.name}","${s.phone||''}","${s.email||''}","${(s.notes||'').replace(/"/g,'""')}"\n`;
    });
  } else if (type === 'movements') {
    filename = 'baro-mouvements.csv';
    csv = 'Date,Article,Type,Quantité,Note\n';
    S.stockMovements.forEach(m => {
      csv += `"${new Date(m.date).toLocaleString()}","${m.article}","${m.type}",${m.qty},"${m.note||''}"\n`;
    });
  } else {
    // Export all
    exportFullCSV('articles');
    exportFullCSV('sales');
    exportFullCSV('clients');
    return;
  }

  const blob = new Blob(['\ufeff' + csv], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = filename; a.click();
  URL.revokeObjectURL(url);
  showToast(t('exportSuccess') + ': ' + filename);
}

// ── LOCATIONS ────────────────────────────────
function addLocation() {
  const nameEl = document.getElementById('loc-name');
  const addrEl = document.getElementById('loc-address');
  const phoneEl = document.getElementById('loc-phone');
  const typeEl = document.getElementById('loc-type');
  const name = nameEl?.value?.trim();
  if (!name) return;
  const loc = {
    id: Date.now(),
    name,
    address: addrEl?.value?.trim() || '',
    phone: phoneEl?.value?.trim() || '',
    type: typeEl?.value || 'store', // store, warehouse, popup
    createdAt: new Date().toISOString()
  };
  S.locations.push(loc);
  localStorage.setItem('baro_locations', JSON.stringify(S.locations));
  S.locationAdd = false;
  logActivity('location', `Nouvel emplacement: ${name}`);
  showToast(`Emplacement "${name}" ajouté`);
  render();
}

function removeLocation(id) {
  const loc = S.locations.find(l => l.id === id);
  if (!confirm(`Supprimer l'emplacement "${loc?.name}" ? Les articles de cet emplacement ne seront plus filtrés.`)) return;
  S.locations = S.locations.filter(l => l.id !== id);
  localStorage.setItem('baro_locations', JSON.stringify(S.locations));
  // Un-assign articles from this location
  S.articles.forEach(a => { if (a.locationId === id) a.locationId = null; });
  localStorage.setItem('baro_articles', JSON.stringify(S.articles));
  if (S.currentLocation === id) {
    S.currentLocation = null;
    localStorage.removeItem('baro_current_location');
  }
  render();
}

function setLocation(id) {
  S.currentLocation = id || null;
  if (id) localStorage.setItem('baro_current_location', String(id));
  else localStorage.removeItem('baro_current_location');
  render();
}

function setArticleLocation(articleId, locationId) {
  const art = S.articles.find(a => a.id === articleId);
  if (!art) return;
  art.locationId = locationId || null;
  localStorage.setItem('baro_articles', JSON.stringify(S.articles));
  showToast(`Emplacement mis à jour`);
}

function getFilteredArticles() {
  if (!S.currentLocation) return S.articles;
  return S.articles.filter(a => !a.locationId || a.locationId === S.currentLocation);
}

function getLocationArticleCount(locId) {
  return S.articles.filter(a => a.locationId === locId).length;
}

function getLocationSalesTotal(locId) {
  const locArticleIds = S.articles.filter(a => a.locationId === locId).map(a => a.id);
  return S.sales.filter(s => {
    const prod = S.products.find(p => p.id === s.productId);
    if (!prod) return false;
    return (prod.composition||[]).some(c => locArticleIds.includes(c.id));
  }).reduce((sum, s) => sum + (s.total || 0), 0);
}

// ── BUSINESS LOGO ────────────────────────────
function uploadLogo() {
  const input = document.createElement('input');
  input.type = 'file'; input.accept = 'image/*';
  input.onchange = () => {
    const file = input.files[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      // Resize to 200x200 max
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const size = Math.min(img.width, img.height, 200);
        canvas.width = size; canvas.height = size;
        const ctx = canvas.getContext('2d');
        const sx = (img.width - size) / 2, sy = (img.height - size) / 2;
        ctx.drawImage(img, sx, sy, size, size, 0, 0, size, size);
        const data = canvas.toDataURL('image/jpeg', 0.8);
        localStorage.setItem('baro_logo', data);
        showToast(t('businessLogo') + ' OK');
        render();
      };
      img.src = e.target.result;
    };
    reader.readAsDataURL(file);
  };
  input.click();
}

