  if (scheduledPostsCount > 0) alerts.push({ icon:'📅', color:'#e1306c', text:`${scheduledPostsCount} publication${scheduledPostsCount>1?'s':''} programmée${scheduledPostsCount>1?'s':''}`, action:"nav('social-media')" });
