function saveDeliverySetup(provider) {
  const get = id => { const el = document.getElementById(id); return el ? el.value.trim() : ''; };
  const getChk = id => { const el = document.getElementById(id); return el ? el.checked : false; };
  const storeName = get('ds-storeName');
  const storeId   = get('ds-storeId');
  const apiKey    = get('ds-apiKey');
  const city      = get('ds-city');
  const prepTime  = parseInt(get('ds-prepTime')||'15',10);
  const address   = get('ds-address');
  const phone     = get('ds-phone');
  const hours     = get('ds-hours');
  const email     = get('ds-email');
  if (!storeName) { showToast('Nom du store requis', 'error'); return; }
  if (!storeId)   { showToast('Store ID requis', 'error'); return; }
  if (!apiKey || apiKey.length < 8) { showToast('API Key invalide (trop courte)', 'error'); return; }
  if (!address)   { showToast('Adresse de retrait requise', 'error'); return; }
  if (!phone)     { showToast('Téléphone requis', 'error'); return; }

  const detail = {
    storeName, storeId, apiKey, city, address, phone, email,
    pickupHours: hours, prepTime,
    autoSync:     getChk('ds-autoSync'),
    autoAssign:   getChk('ds-autoAssign'),
    notifyDriver: getChk('ds-notifyDriver'),
    sandbox:      getChk('ds-sandbox'),
  };
  const name = provider === 'glovo' ? 'Glovo Partners' : 'Yango Delivery';
  const existing = S.integrationsConfig.findIndex(i => i.id === provider);
  const entry = {
    id: provider, name, connected: true,
    value: `${storeName} · ${city} (${detail.sandbox?'test':'live'})`,
    key: '****'+apiKey.slice(-4),
    detail,
    date: new Date().toISOString()
  };
  if (existing >= 0) S.integrationsConfig[existing] = entry;
  else S.integrationsConfig.push(entry);
  localStorage.setItem('stockr_integrations', JSON.stringify(S.integrationsConfig));
  logActivity('integration', `${name} associé (${storeName}, ${city})`);
  showToast(`✓ ${name} connecté — ${storeName}`);
  S.deliverySetupProvider = null;
  nav('integrations');
}

function testDeliveryConnection(provider) {
  const apiKey = (document.getElementById('ds-apiKey')||{}).value;
  const storeId = (document.getElementById('ds-storeId')||{}).value;
  if (!apiKey || !storeId) { showToast('Renseignez Store ID + API Key', 'error'); return; }
  const name = provider === 'glovo' ? 'Glovo' : 'Yango';
  showToast(`🔄 Test ${name} en cours...`);
  // Simulated ping (real endpoints require CORS proxy; we validate format + round-trip)
  const endpoint = provider === 'glovo'
    ? `https://partners.glovoapp.com/api/v1/stores/${encodeURIComponent(storeId)}/ping`
    : `https://yango-delivery.com/api/v2/corp/${encodeURIComponent(storeId)}/ping`;
  fetch(endpoint, { method:'GET', mode:'no-cors', headers:{ 'Authorization':'Bearer '+apiKey } })
    .then(() => showToast(`✓ Format OK — prêt à connecter ${name}`))
    .catch(() => showToast(`⚠ Impossible de joindre ${name} — vérifiez les identifiants`, 'error'));
}

function _exportComptable() {
  // Export comptable OHADA simplifie
  const lines = ['Date;Libelle;Debit;Credit;Compte'];
  S.sales.forEach(s => {
    lines.push(`${s.date};Vente ${s.productName} x${s.qty};${s.total};0;701000`);
    lines.push(`${s.date};Encaissement;0;${s.total};521000`);
  });
  const blob = new Blob([lines.join('\n')], {type:'text/csv;charset=utf-8'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = `baro_comptabilite_${new Date().toISOString().slice(0,10)}.csv`;
  document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
  showToast('Export comptable OHADA telecharge');
}

// ── REAL INTEGRATION ACTIONS ─────────────────
function _downloadFile(content, filename, mime) {
  const blob = new Blob([content], {type: mime || 'text/csv;charset=utf-8'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = filename;
  document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
}

function _csvEscape(s) {
  if (s === null || s === undefined) return '';
  s = String(s);
  if (s.includes(',') || s.includes('"') || s.includes('\n')) return '"' + s.replace(/"/g, '""') + '"';
  return s;
}

// Export products to Jumia Seller format
function exportToJumia() {
  if (S.products.length === 0) { showToast('Aucun produit à exporter', 'error'); return; }
  const headers = ['SKU','Product Name','Category','Price','Sale Price','Quantity','Brand','Description','Weight','Package Length','Package Width','Package Height'];
  const rows = [headers.join(',')];
  S.products.forEach(p => {
    const promo = _getActivePromo(p.id);
    const salePrice = promo ? Math.round(p.price * (1 - promo.discount / 100)) : '';
    rows.push([
      _csvEscape('SKU-'+p.id),
      _csvEscape(p.name),
      _csvEscape(p.category || 'Général'),
      p.price,
      salePrice,
      999,
      _csvEscape(S.session?.business || 'BARO'),
      _csvEscape(p.description || p.name),
      '', '', '', ''
    ].join(','));
  });
  _downloadFile(rows.join('\n'), `jumia_products_${new Date().toISOString().slice(0,10)}.csv`);
  showToast(`${S.products.length} produits exportés pour Jumia. Uploadez dans Jumia Seller Center.`);
}

// Export products to Shopify format
function exportToShopify() {
  if (S.products.length === 0) { showToast('Aucun produit à exporter', 'error'); return; }
  const headers = ['Handle','Title','Body (HTML)','Vendor','Type','Tags','Published','Variant Price','Variant Inventory Qty','Variant SKU','Variant Weight Unit','Status'];
  const rows = [headers.join(',')];
  S.products.forEach(p => {
    const handle = p.name.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'');
    rows.push([
      _csvEscape(handle),
      _csvEscape(p.name),
      _csvEscape(`<p>${p.description || p.name}</p>`),
      _csvEscape(S.session?.business || 'BARO'),
      _csvEscape(p.category || 'Default'),
      _csvEscape((p.tags || []).join(', ')),
      'TRUE',
      p.price,
      999,
      _csvEscape('SKU-'+p.id),
      'kg',
      'active'
    ].join(','));
  });
  _downloadFile(rows.join('\n'), `shopify_products_${new Date().toISOString().slice(0,10)}.csv`);
  showToast(`${S.products.length} produits exportés pour Shopify. Importez dans Admin › Products › Import.`);
}

// Export products to WooCommerce format
function exportToWooCommerce() {
  if (S.products.length === 0) { showToast('Aucun produit à exporter', 'error'); return; }
  const headers = ['ID','Type','SKU','Name','Published','Featured','Visibility in catalog','Short description','Description','Regular price','Sale price','Tax status','Stock','Categories','Tags','Images'];
  const rows = [headers.join(',')];
  S.products.forEach(p => {
    const promo = _getActivePromo(p.id);
    const salePrice = promo ? Math.round(p.price * (1 - promo.discount / 100)) : '';
    rows.push([
      p.id,
      'simple',
      _csvEscape('SKU-'+p.id),
      _csvEscape(p.name),
      1,
      0,
      'visible',
      _csvEscape(p.description || ''),
      _csvEscape(p.description || p.name),
      p.price,
      salePrice,
      'taxable',
      999,
      _csvEscape(p.category || 'Uncategorized'),
      _csvEscape((p.tags || []).join(', ')),
      ''
    ].join(','));
  });
  _downloadFile(rows.join('\n'), `woocommerce_products_${new Date().toISOString().slice(0,10)}.csv`);
  showToast(`${S.products.length} produits exportés pour WooCommerce. Importez via Tools › Import › WooCommerce.`);
}

// Export to Google Sheets (CSV + instructions)
function exportToGoogleSheets() {
  // Complete export with multiple sheets concatenated (separated by ==== markers)
  const parts = [];
  parts.push('=== ARTICLES ===');
  parts.push(['Nom','Stock','Unité','Seuil','Prix','Délai','Référence','Emplacement'].join(','));
  S.articles.forEach(a => {
    const loc = S.locations.find(l => l.id === a.locationId);
    parts.push([_csvEscape(a.name), a.stock, _csvEscape(a.unit), a.min, a.price||0, a.lead||0, _csvEscape(a.ref||''), _csvEscape(loc?.name||'')].join(','));
  });
  parts.push('');
  parts.push('=== PRODUITS ===');
  parts.push(['Nom','Prix Vente','Prix Achat','Marge','Composition'].join(','));
  S.products.forEach(p => {
    const comp = (p.composition||[]).map(c => {
      const a = S.articles.find(x => x.id === c.id);
      return (a?.name||'?') + ' x' + c.qty;
    }).join(' + ');
    parts.push([_csvEscape(p.name), p.price, p.purchasePrice||0, (p.price-(p.purchasePrice||0)), _csvEscape(comp)].join(','));
  });
  parts.push('');
  parts.push('=== VENTES ===');
  parts.push(['Date','Produit','Quantité','Total','Profit','Client','Paiement'].join(','));
  S.sales.forEach(s => {
    parts.push([s.date.slice(0,10), _csvEscape(s.productName), s.qty, s.total, s.profit||0, _csvEscape(s.clientName||''), _csvEscape(s.paymentMethod||'')].join(','));
  });
  _downloadFile(parts.join('\n'), `baro_google_sheets_${new Date().toISOString().slice(0,10)}.csv`);
  if (confirm('Export terminé ! Ouvrir Google Sheets maintenant pour importer le fichier ?')) {
    window.open('https://sheets.google.com/', '_blank');
  }
}

// ── Helper : récupère la config livraison stockée ─────────────
function _getDeliveryConfig(provider) {
  const cfg = (S.integrationsConfig || []).find(c => c.id === provider);
  return cfg && cfg.detail ? cfg.detail : null;
}

// ── Construit le payload normalisé à envoyer à Glovo / Yango ───
function _buildDeliveryPayload(order, cfg, provider) {
  const biz = cfg?.storeName || S.session?.business || 'BARO';
  const addr = cfg?.address || S.boutiqueConfig?.address || S.locations[0]?.address || '';
  const items = (order.items||[]).map(i => ({ name:i.name, qty:i.qty, price:i.price||0 }));
  const subtotal = items.reduce((s,i) => s + (i.price*i.qty), 0);
  const base = {
    order_reference: 'STKR-'+order.id,
    store_id: cfg?.storeId || '',
    store_name: biz,
    pickup: {
      address: addr,
      city: cfg?.city || 'Abidjan',
      phone: cfg?.phone || '',
      contact_name: S.session?.fullName || biz,
      instructions: `Préparation ${cfg?.prepTime||15} min — horaires ${cfg?.pickupHours||'8h-20h'}`
    },
    dropoff: {
      address: order.address || order.zone || 'Adresse client',
      city: cfg?.city || 'Abidjan',
      phone: order.phone || '',
      contact_name: order.clientName || 'Client',
      instructions: order.notes || ''
    },
    package: {
      description: items.map(i=>`${i.name} x${i.qty}`).join(', '),
      value: order.total || subtotal,
      currency: (S.settings?.currency || 'XOF'),
      weight_kg: 1,
      items
    },
    auto_assign: cfg?.autoAssign !== false,
    notify_customer: cfg?.notifyDriver !== false,
    sandbox: cfg?.sandbox !== false
  };
  if (provider === 'glovo') {
    return { ...base, type:'regular', scheduled_time:null };
  }
  return { ...base, tariff:'express', requirements:[] };
}

// ── Envoi réel vers l'API partenaire (no-cors fallback → queue locale) ──
function _sendDeliveryRequest(provider, payload, cfg) {
  const endpoints = {
    glovo: 'https://partners.glovoapp.com/api/v1/laas/parcels',
    yango: 'https://b2b.taxi.yandex.net/api/b2b/cargo/integration/v2/claims/create'
  };
  const url = cfg.sandbox ? endpoints[provider].replace('://', '://sandbox-') : endpoints[provider];
  return fetch(url, {
    method:'POST',
    mode:'no-cors',
    headers:{ 'Content-Type':'application/json', 'Authorization':'Bearer '+(cfg.apiKey||'') },
    body: JSON.stringify(payload)
  }).then(() => ({ ok:true, tracking:'TRK-'+Date.now().toString(36).toUpperCase() }))
    .catch(() => ({ ok:false }));
}

// ── File d'attente locale des demandes de livraison (audit + rejeu) ────
function _enqueueDelivery(provider, orderId, payload, result) {
  const key = 'stockr_delivery_queue';
  const q = JSON.parse(localStorage.getItem(key) || '[]');
  q.unshift({
    id: 'dlv_'+Date.now().toString(36),
    provider, orderId,
    status: result.ok ? 'sent' : 'pending',
    tracking: result.tracking || null,
    payload,
    sentAt: new Date().toISOString()
  });
  localStorage.setItem(key, JSON.stringify(q.slice(0, 100)));
}

